import type { ExamQuestion } from "./types";

export const rnPathoCardioNeuroCatQuestions: ExamQuestion[] = [
  // ===== MI — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four patients. Which should be assessed FIRST?\n\n1. Post-MI day 2 with HR 72, BP 118/74, and occasional PVCs on telemetry\n2. Acute STEMI patient with new ST elevation in V1-V4 and crushing chest pain\n3. NSTEMI patient awaiting cardiac catheterization, currently pain-free\n4. Post-PCI patient 6 hours out with stable vitals and intact femoral site", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 has an acute STEMI — a life-threatening emergency requiring emergent PCI within 90 minutes. The other patients are stable or have non-emergent needs.", s: "Cardiovascular" },
  { q: "A nurse delegates care for four MI patients. Which task is appropriate to assign to an LPN?", o: ["Performing initial post-PCI assessment on the new admission", "Administering scheduled oral aspirin and atorvastatin to a stable day-2 post-MI patient", "Titrating the IV heparin drip based on aPTT results", "Teaching the patient about dual antiplatelet therapy and lifestyle modifications"], a: 1, r: "LPNs can administer scheduled oral medications to stable patients. Initial assessments, IV drip titration, and complex discharge teaching require RN judgment.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which finding requires the MOST urgent intervention?\n\n1. Post-MI patient with troponin trending down from 8.2 to 5.1\n2. Post-MI day 5 patient with new holosystolic murmur and sudden hypotension\n3. NSTEMI patient with BP 142/88 and headache\n4. Post-PCI patient with 2 cm ecchymosis at femoral site", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "New murmur + sudden hypotension on day 5 post-MI = mechanical complication (VSD or papillary muscle rupture). This is a surgical emergency. Other findings are expected or non-emergent.", s: "Cardiovascular" },
  { q: "A charge nurse is assigning four post-MI patients. Which patient is MOST appropriate to assign to a new graduate nurse?", o: ["STEMI patient returning from emergent PCI with multiple IV drips", "Stable day-3 post-MI patient awaiting discharge teaching", "Cardiogenic shock patient on IABP and vasopressors", "Post-MI patient with new-onset ventricular tachycardia"], a: 1, r: "The stable day-3 patient awaiting discharge is the most appropriate for a new graduate — predictable care needs with lower acuity. The others require experienced critical care nursing judgment.", s: "Cardiovascular" },
  { q: "A nurse receives four lab results for MI patients. Which requires IMMEDIATE provider notification?\n\n1. Troponin I 2.4 ng/mL (initial presentation)\n2. aPTT 115 seconds (target 60-80) on heparin drip\n3. Potassium 4.2 mEq/L\n4. BNP 180 pg/mL", o: ["Result 1", "Result 2", "Result 3", "Result 4"], a: 1, r: "aPTT 115 is dangerously supratherapeutic, indicating high hemorrhage risk. The heparin should be held and the provider notified immediately per protocol. The other values are expected or within normal limits.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients with chest pain. Which patient's presentation is MOST consistent with acute MI rather than another cause?\n\n1. Sharp chest pain worsened by deep breathing, relieved by leaning forward\n2. Substernal pressure radiating to the left arm with diaphoresis, lasting 40 minutes\n3. Chest pain that reproduces with palpation of the chest wall\n4. Burning epigastric pain worsened by lying flat, relieved by antacids", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Substernal pressure with radiation, diaphoresis, and prolonged duration is classic MI. Patient 1 = pericarditis, Patient 3 = musculoskeletal, Patient 4 = GERD.", s: "Cardiovascular" },
  { q: "A nurse is managing four post-MI patients and must administer time-sensitive medications. Which medication should be given FIRST?", o: ["Atorvastatin 80 mg PO at bedtime for patient A", "Metoprolol 25 mg PO for patient B (HR 78, BP 128/76)", "Aspirin 325 mg chewed for patient C presenting with active STEMI", "Docusate sodium for patient D requesting a bowel movement"], a: 2, r: "Aspirin for active STEMI is the most time-sensitive — every minute of platelet inhibition delay worsens infarct size. The other medications are important but not emergent.", s: "Cardiovascular" },
  { q: "Four patients call the nurse simultaneously. Which should the nurse respond to FIRST?\n\n1. Post-MI patient reporting anxiety about upcoming discharge\n2. Post-PCI patient reporting sudden numbness and pallor of the right foot\n3. Post-MI patient requesting pain medication for a headache (rated 4/10)\n4. Post-MI patient asking about their cardiac rehabilitation schedule", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Sudden numbness and pallor of the foot post-PCI suggests acute limb ischemia from arterial occlusion or embolization — a vascular emergency requiring immediate assessment and intervention.", s: "Cardiovascular" },
  { q: "A nurse is reviewing medication administration records for four MI patients. Which entry indicates a potential ERROR requiring clarification?", o: ["Aspirin 81 mg PO daily given with ticagrelor", "Nitroglycerin SL given to patient who took sildenafil 8 hours ago", "Metoprolol succinate 50 mg PO given with HR 64 and BP 112/68", "Enoxaparin 1 mg/kg SubQ given for NSTEMI management"], a: 1, r: "Nitroglycerin within 24 hours of sildenafil (PDE5 inhibitor) is contraindicated — risk of severe, potentially fatal hypotension. This must be immediately addressed.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which task can be safely delegated to a UAP?\n\n1. Obtaining daily weight and vital signs on a stable post-MI patient\n2. Administering sublingual nitroglycerin for chest pain\n3. Assessing chest pain quality using the PQRST format\n4. Interpreting the cardiac rhythm on the telemetry monitor", o: ["Task 1", "Task 2", "Task 3", "Task 4"], a: 0, r: "Daily weights and vital signs on stable patients are within UAP scope. Medication administration, pain assessment, and rhythm interpretation all require nursing licensure.", s: "Cardiovascular" },
  { q: "A nurse is triaging four patients arriving to the ED. Which should be seen FIRST?\n\n1. 62-year-old with chest pain for 90 minutes and ST elevation in II, III, aVF\n2. 45-year-old with intermittent chest pain with exertion × 3 months\n3. 70-year-old with GERD-like symptoms after a large meal\n4. 55-year-old with chest wall tenderness after moving furniture", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 0, r: "Active STEMI for 90 minutes is the highest priority — door-to-balloon goal is <90 minutes. Every minute of delay increases infarct size and mortality.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which assessment finding indicates the patient's condition is DETERIORATING?\n\n1. Post-MI patient with resolving ST elevation and pain score 0/10\n2. Post-MI patient with stable HR 68 and regular sinus rhythm\n3. Post-MI patient developing new S3 gallop, increasing crackles, and SpO2 dropping to 89%\n4. Post-MI patient with troponin trending down", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 2, r: "New S3, increasing crackles, and dropping SpO2 indicate developing heart failure and pulmonary edema — the patient is decompensating and needs immediate intervention (diuretics, oxygen, provider notification).", s: "Cardiovascular" },
  { q: "A nurse is preparing four MI patients for discharge. Which patient statement requires ADDITIONAL teaching?\n\n1. \"I will take my aspirin every morning with breakfast\"\n2. \"I will call 911 if I have chest pain that doesn't go away after one nitroglycerin\"\n3. \"I can stop my statin once my cholesterol normalizes\"\n4. \"I enrolled in cardiac rehabilitation starting next week\"", o: ["Statement 1", "Statement 2", "Statement 3", "Statement 4"], a: 2, r: "Statins should never be stopped even when cholesterol normalizes — they provide pleiotropic benefits (plaque stabilization, anti-inflammatory) beyond just lipid lowering. The patient needs re-education.", s: "Cardiovascular" },
  { q: "A nurse receives report on four MI patients. Which should be assessed FIRST at the beginning of the shift?\n\n1. Post-MI day 1 with HR 88, BP 130/82, pain 0/10, normal rhythm\n2. Post-MI day 3 with low-grade fever, pericardial friction rub, and pleuritic chest pain\n3. Post-MI day 5 with sudden PEA arrest — code team has been called\n4. Post-PCI day 1 with intact groin site, pedal pulses present", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 2, r: "Active PEA arrest (likely free wall rupture day 5 post-MI) requires immediate nursing response to assist with resuscitation. The code team is coming but the nurse must respond immediately.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients on anticoagulation therapy for ACS. Which lab result requires the nurse to HOLD the medication and notify the provider?\n\n1. INR 2.5 on warfarin (target 2-3)\n2. Platelet count 42,000/μL on heparin drip (was 180,000 three days ago)\n3. aPTT 72 seconds on heparin (target 60-80)\n4. Hemoglobin 13.2 g/dL", o: ["Result 1", "Result 2", "Result 3", "Result 4"], a: 1, r: "Platelet count drop >50% (180K → 42K) on heparin = suspected HIT (heparin-induced thrombocytopenia). ALL heparin must be stopped immediately and an alternative anticoagulant started. HIT paradoxically causes thrombosis.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which can be SAFELY discharged today?\n\n1. Post-MI patient with persistent ST elevation and ongoing chest pain\n2. Post-MI patient day 3, asymptomatic, on optimal GDMT, with follow-up arranged\n3. NSTEMI patient with troponin still rising\n4. Post-MI patient with new-onset atrial fibrillation and rapid ventricular response", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "The asymptomatic day-3 post-MI patient on appropriate medications with arranged follow-up is the safest for discharge. The others have active or unresolved issues requiring continued hospitalization.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which medication interaction should the nurse question?\n\n1. Aspirin 81 mg + clopidogrel for post-PCI patient\n2. Metoprolol + lisinopril for post-MI patient\n3. Ticagrelor + aspirin 325 mg for ACS patient\n4. Atorvastatin + ezetimibe for hyperlipidemia", o: ["Combination 1", "Combination 2", "Combination 3", "Combination 4"], a: 2, r: "Ticagrelor effectiveness is reduced with aspirin doses >100 mg per PLATO trial data. The combination should use aspirin 81 mg, not 325 mg. The nurse should clarify with the prescriber.", s: "Cardiovascular" },
  { q: "A nurse is reviewing cardiac catheterization results for four patients. Which finding indicates the HIGHEST-risk coronary anatomy?\n\n1. 50% stenosis of the right coronary artery\n2. 95% stenosis of the left main coronary artery\n3. 70% stenosis of the left circumflex artery\n4. 60% stenosis of the first diagonal branch", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Left main coronary artery stenosis is the highest-risk anatomy — it supplies 75% of the left ventricular myocardium. 95% left main stenosis requires urgent CABG and carries the highest mortality if untreated.", s: "Cardiovascular" },
  { q: "A nurse is managing four post-MI patients' medications at 0800. Which medication should be administered FIRST?\n\n1. Atorvastatin 80 mg PO for patient with stable lipids\n2. Aspirin 81 mg PO for secondary prevention\n3. IV nitroglycerin for patient with recurrent chest pain rated 7/10\n4. Docusate sodium for constipation prevention", o: ["Medication 1", "Medication 2", "Medication 3", "Medication 4"], a: 2, r: "Active chest pain requires the most urgent medication intervention. IV nitroglycerin for ongoing ischemic pain takes priority over maintenance medications that can be given within a reasonable timeframe.", s: "Cardiovascular" },
  { q: "A nurse identifies four patients who need education before discharge. Which teaching topic is the HIGHEST priority for patient safety?\n\n1. When to return to work\n2. When to call 911 (chest pain protocol with NTG)\n3. Dietary recommendations for heart health\n4. Exercise guidelines from cardiac rehab", o: ["Topic 1", "Topic 2", "Topic 3", "Topic 4"], a: 1, r: "Knowing when to call 911 is the highest priority safety teaching — delays in seeking emergency care for recurrent MI are potentially fatal. Take 1 NTG, if no relief in 5 minutes, call 911.", s: "Cardiovascular" },

  // ===== HEART FAILURE — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four heart failure patients. Which should be assessed FIRST?\n\n1. HFrEF patient with EF 35% on stable GDMT, asking about sodium intake\n2. HFrEF patient with new-onset pink frothy sputum and SpO2 84%\n3. HFpEF patient with BP 138/84 and mild peripheral edema\n4. HF patient who gained 1 pound since yesterday", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Pink frothy sputum with SpO2 84% = acute pulmonary edema, a life-threatening emergency requiring emergent IV diuretics, oxygen, and possibly NIPPV. This patient is in respiratory distress.", s: "Cardiovascular" },
  { q: "A nurse must delegate tasks for four HF patients. Which is appropriate for a UAP?", o: ["Administering IV furosemide for acute decompensation", "Measuring daily weight and recording strict I&O", "Assessing breath sounds for crackles", "Teaching about the HF zone management system"], a: 1, r: "Daily weights and I&O are routine measurements within UAP scope. Medication administration, lung auscultation, and complex patient education require RN judgment.", s: "Cardiovascular" },
  { q: "A nurse is reviewing labs for four HF patients. Which result requires IMMEDIATE action?\n\n1. BNP 450 pg/mL in newly diagnosed HF\n2. Potassium 2.8 mEq/L in patient on furosemide\n3. Sodium 136 mEq/L\n4. Creatinine 1.1 mg/dL", o: ["Result 1", "Result 2", "Result 3", "Result 4"], a: 1, r: "K+ 2.8 is critically low and can cause fatal cardiac arrhythmias, especially in patients on digoxin. Requires immediate potassium replacement and provider notification. Hold loop diuretics.", s: "Cardiovascular" },
  { q: "A nurse is managing medications for four HF patients. Which order should the nurse QUESTION?\n\n1. Carvedilol 6.25 mg BID for stable HFrEF\n2. Metoprolol tartrate 50 mg BID for newly diagnosed HFrEF\n3. Sacubitril/valsartan for HFrEF with EF 30%\n4. Spironolactone 25 mg daily with K+ monitoring", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 1, r: "Metoprolol TARTRATE is not evidence-based for HFrEF. Only metoprolol SUCCINATE (extended-release) has mortality data. The nurse should question this and suggest the appropriate formulation.", s: "Cardiovascular" },
  { q: "A nurse is caring for four HF patients. Which combination of findings indicates the WORST prognosis?\n\n1. EF 40%, BNP 200, NYHA Class II\n2. EF 15%, BNP 2800, Na+ 126, refractory to diuretics\n3. EF 55%, BNP 150, mild dyspnea on exertion\n4. EF 35%, BNP 400, stable on GDMT", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "EF 15% + BNP 2800 + hyponatremia (126) + diuretic resistance = Stage D refractory HF with multiple poor prognostic indicators. This patient should be evaluated for advanced therapies (LVAD, transplant).", s: "Cardiovascular" },
  { q: "A nurse receives four new medication orders for an HFrEF patient. Which combination creates the HIGHEST risk for hyperkalemia?\n\n1. Furosemide + metolazone\n2. Lisinopril + spironolactone\n3. Carvedilol + furosemide\n4. Hydralazine + isosorbide dinitrate", o: ["Combination 1", "Combination 2", "Combination 3", "Combination 4"], a: 1, r: "ACEi (lisinopril) + MRA (spironolactone) = both potassium-sparing. Combined use significantly increases hyperkalemia risk. Monitor K+ within 1 week of initiation and frequently thereafter.", s: "Cardiovascular" },
  { q: "A nurse is prioritizing four HF patients at shift change. Which should be assessed FIRST?\n\n1. HF patient asking about fluid restriction guidelines\n2. HF patient with weight gain of 5 pounds in 2 days, increasing dyspnea, and new crackles\n3. Stable HF patient requesting evening medications\n4. HF patient with appointment for echocardiogram tomorrow", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Rapid weight gain (5 lbs in 2 days) with increasing dyspnea and new crackles = acute decompensation requiring immediate assessment, provider notification, and likely IV diuretic intensification.", s: "Cardiovascular" },
  { q: "A charge nurse is making patient assignments. Which HF patient is MOST appropriate for a float nurse unfamiliar with the cardiac unit?", o: ["Patient on milrinone drip requiring hourly hemodynamic monitoring", "Stable HF patient on oral GDMT awaiting echocardiogram", "Patient on IABP and multiple vasopressors in cardiogenic shock", "Patient with new BiV-ICD being interrogated today"], a: 1, r: "The stable HF patient on oral medications with a routine diagnostic test is the most predictable and safest assignment for a float nurse unfamiliar with complex cardiac equipment and protocols.", s: "Cardiovascular" },
  { q: "A nurse is evaluating four HF patients' understanding of self-management. Which statement indicates the patient NEEDS more teaching?", o: ["\"I weigh myself every morning on the same scale before breakfast\"", "\"I limit my sodium to less than 2 grams per day\"", "\"I stop taking my carvedilol when I feel better because I don't want side effects\"", "\"I will call my doctor if I gain more than 2 pounds in one day\""], a: 2, r: "Stopping a beta-blocker because of feeling better is dangerous — abrupt discontinuation can cause rebound tachycardia and HF decompensation. GDMT must be taken consistently regardless of how the patient feels.", s: "Cardiovascular" },
  { q: "A nurse is managing four HF patients on diuretic therapy. Which combination indicates diuretic resistance requiring provider notification?\n\n1. Furosemide 40 mg IV with 800 mL urine output in 2 hours\n2. Furosemide 160 mg IV with only 200 mL urine output in 4 hours despite adequate BP\n3. Bumetanide 1 mg IV with 600 mL output in 2 hours\n4. Furosemide 20 mg PO with 400 mL output over 4 hours", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "High-dose furosemide (160 mg IV) with minimal output (200 mL/4 hr) despite adequate perfusion = diuretic resistance. Provider should be notified for sequential nephron blockade (add metolazone) or consider ultrafiltration.", s: "Cardiovascular" },
  { q: "A nurse is reviewing four HF patients' medication lists. Which patient is missing a critical GDMT component?\n\n1. HFrEF (EF 28%): lisinopril, carvedilol, spironolactone, empagliflozin, furosemide\n2. HFrEF (EF 25%): sacubitril/valsartan, metoprolol succinate, furosemide\n3. HFpEF (EF 60%): empagliflozin, diuretic\n4. HFrEF (EF 30%): lisinopril, carvedilol, spironolactone, dapagliflozin", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 is missing an MRA (spironolactone/eplerenone) and SGLT2i — two of the four GDMT pillars. Patient 1 has all four pillars. The nurse should discuss adding the missing components.", s: "Cardiovascular" },
  { q: "A nurse is transitioning an HFrEF patient from lisinopril to sacubitril/valsartan. Which nursing action is MOST important?", o: ["Give both medications simultaneously to ensure seamless transition", "Verify the 36-hour washout period from last ACEi dose before starting Entresto", "Check BNP level before starting", "Monitor for hyperkalemia only"], a: 1, r: "A mandatory 36-hour washout from ACEi is required before starting sacubitril/valsartan to prevent life-threatening angioedema from excessive bradykinin accumulation. Simultaneous administration is dangerous.", s: "Cardiovascular" },
  { q: "A nurse is caring for four HF patients receiving IV diuretics. Which assessment combination BEST indicates improving volume status?", o: ["Rising BNP with stable weight", "Decreasing weight, clearing crackles, improving SpO2, and increasing urine output", "Stable edema with unchanged dyspnea", "Decreasing urine output with stable weight"], a: 1, r: "Improving volume status: weight loss (fluid removal), clearing crackles (decreased pulmonary congestion), improving oxygenation, and adequate urine output. This multi-parameter assessment is more reliable than any single indicator.", s: "Cardiovascular" },
  { q: "A nurse is preparing to start a new beta-blocker for an HFrEF patient. Which patient condition requires the nurse to HOLD the medication and notify the provider?", o: ["HR 62, BP 108/68, no symptoms — stable on current GDMT", "HR 48, BP 84/52, complaints of dizziness and near-syncope", "HR 78, BP 124/76, mild fatigue", "HR 70, BP 116/72, requesting lunch"], a: 1, r: "HR 48 with hypotension (84/52) and symptoms (dizziness, near-syncope) = symptomatic bradycardia. Starting or continuing a beta-blocker would worsen this. Hold and notify the provider.", s: "Cardiovascular" },
  { q: "A nurse is evaluating four HF patients' daily weights. Which patient's weight change requires the MOST urgent provider notification?\n\n1. Lost 0.5 kg overnight on IV furosemide (expected)\n2. Gained 3 kg (6.6 lbs) in 2 days with worsening dyspnea\n3. Stable weight × 3 days on maintenance diuretics\n4. Lost 1 kg overnight on aggressive diuresis (ordered)", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Weight gain of 3 kg in 2 days with worsening symptoms = acute fluid retention and decompensation. This exceeds the 2 lb/day threshold and requires immediate intervention.", s: "Cardiovascular" },
  { q: "A nurse is caring for four HF patients. Which finding suggests cardiorenal syndrome?\n\n1. BNP decreasing with diuresis\n2. Creatinine rising from 1.2 to 2.8 during aggressive diuresis\n3. Potassium 4.0 mEq/L on spironolactone\n4. Hemoglobin stable at 12.5 g/dL", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Rising creatinine during aggressive diuresis indicates cardiorenal syndrome — renal hypoperfusion from excessive preload reduction. The clinical challenge is balancing decongestion with maintaining adequate renal perfusion.", s: "Cardiovascular" },
  { q: "A nurse is caring for four HF patients. Which patient is at HIGHEST risk for digoxin toxicity?\n\n1. HF patient with K+ 4.5, Cr 1.0, digoxin level 1.2\n2. HF patient with K+ 2.9, Cr 2.8, digoxin level 1.8\n3. HF patient with K+ 4.0, Cr 1.1, digoxin level 0.8\n4. HF patient not on digoxin", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 has three risk factors for dig toxicity: hypokalemia (K+ 2.9 — potassium and digoxin compete for the same binding site), renal impairment (Cr 2.8 — digoxin is renally cleared), and borderline-high digoxin level (1.8).", s: "Cardiovascular" },
  { q: "A nurse is receiving report on four HF patients. Which Nohria-Stevenson profile has the WORST prognosis?\n\n1. Warm and dry (Profile A — compensated)\n2. Warm and wet (Profile B — congested but perfusing)\n3. Cold and dry (Profile L — hypoperfused without congestion)\n4. Cold and wet (Profile C — congested AND hypoperfused)", o: ["Profile A", "Profile B", "Profile L", "Profile C"], a: 3, r: "Cold and wet (Profile C) = cardiogenic shock with both congestion AND hypoperfusion. This carries the worst prognosis and requires inotropes/vasopressors plus diuretics.", s: "Cardiovascular" },
  { q: "A nurse is educating four HF patients about the zone management system. Which patient response indicates CORRECT understanding of the RED zone?", o: ["\"I gained 2 pounds — I should call my doctor\"", "\"I have severe shortness of breath at rest, can't breathe lying down, and feel confused — I should call 911\"", "\"I feel fine and have no swelling — I continue my medications\"", "\"I have mild ankle swelling — I should reduce my sodium\""], a: 1, r: "Red zone = emergency (severe SOB at rest, can't breathe lying down, confusion, chest pain → call 911). Yellow zone = call doctor (weight gain, increased swelling). Green zone = stable (continue routine).", s: "Cardiovascular" },
  { q: "A nurse is caring for four HF patients. Which combination of medications should the nurse question for a patient with HFrEF?\n\n1. Sacubitril/valsartan + metoprolol succinate + spironolactone + dapagliflozin\n2. Diltiazem + verapamil for HFrEF\n3. Lisinopril + carvedilol + eplerenone + empagliflozin\n4. Hydralazine + isosorbide dinitrate + carvedilol for ACEi-intolerant patient", o: ["Combination 1", "Combination 2", "Combination 3", "Combination 4"], a: 1, r: "Non-dihydropyridine calcium channel blockers (diltiazem, verapamil) are CONTRAINDICATED in HFrEF — their negative inotropic effect worsens systolic function. Additionally, combining two CCBs is dangerous (severe bradycardia, heart block).", s: "Cardiovascular" },

  // ===== CAD — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four patients with chest pain. Which should be assessed FIRST?\n\n1. Patient with stable angina reporting typical exertional discomfort that resolved with rest\n2. Patient with new-onset rest angina, diaphoresis, and nausea\n3. Patient with GERD-like burning and belching\n4. Patient with reproducible chest wall tenderness", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "New-onset rest angina with associated symptoms (diaphoresis, nausea) = unstable angina/ACS until proven otherwise. This is potentially life-threatening and requires immediate evaluation.", s: "Cardiovascular" },
  { q: "A nurse is delegating care for CAD patients in a cardiac clinic. Which task is appropriate for an LPN?", o: ["Performing stress test interpretation", "Administering scheduled oral cardiac medications to stable patients", "Developing individualized cardiac rehabilitation plans", "Performing initial cardiac risk assessment for new patients"], a: 1, r: "LPNs can administer scheduled oral medications to stable patients. Stress test interpretation, care planning, and initial comprehensive assessments require RN-level judgment.", s: "Cardiovascular" },
  { q: "A nurse is educating four CAD patients about NTG use. Which patient statement requires CORRECTION?\n\n1. \"I keep my NTG in its dark glass bottle\"\n2. \"I check my blood pressure before taking NTG\"\n3. \"I take three NTG tablets 5 minutes apart, then call 911 if still hurting\"\n4. \"I replace my NTG every 6 months\"", o: ["Statement 1", "Statement 2", "Statement 3", "Statement 4"], a: 2, r: "Current AHA guideline: take ONE NTG tablet, if no relief in 5 minutes, call 911. The old 3-tablet protocol has been replaced. Earlier 911 activation saves lives.", s: "Cardiovascular" },
  { q: "A nurse is reviewing lipid panels for four CAD patients. Which patient's LDL requires the MOST urgent intervention?\n\n1. Primary prevention patient with LDL 145 mg/dL\n2. Post-CABG patient with LDL 110 mg/dL on moderate-intensity statin\n3. Post-MI patient with LDL 92 mg/dL on high-intensity statin\n4. Healthy 30-year-old with LDL 120 mg/dL", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Post-CABG patient (established CAD) with LDL 110 — goal is <70 mg/dL. This patient needs statin intensification. They are significantly above the secondary prevention target despite treatment.", s: "Cardiovascular" },
  { q: "A nurse is managing four patients. Which statin side effect requires IMMEDIATE reporting?\n\n1. Mild headache starting a new statin\n2. Bilateral thigh pain with dark cola-colored urine on atorvastatin\n3. Mild constipation\n4. Slight increase in fasting glucose", o: ["Side effect 1", "Side effect 2", "Side effect 3", "Side effect 4"], a: 1, r: "Muscle pain with dark urine = possible rhabdomyolysis (muscle breakdown releasing myoglobin). This can cause acute kidney injury. Requires immediate CK level check and possible statin discontinuation.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients with angina. Which patient's pain pattern indicates UNSTABLE angina requiring emergent evaluation?\n\n1. Chest pressure with climbing 2 flights of stairs, consistent × 1 year, relieved with rest\n2. Chest pain at rest that occurs unpredictably and lasts 20+ minutes despite NTG\n3. Chest tightness with strenuous exercise, relieved in 5 minutes\n4. Occasional chest ache with heavy meals", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Rest angina lasting >20 minutes unrelieved by NTG = unstable angina. This represents acute plaque disruption with thrombus formation and requires emergent ACS evaluation (ECG, troponin, possible cath).", s: "Cardiovascular" },
  { q: "A nurse is prioritizing education for four CAD patients being discharged. Which modifiable risk factor, when addressed, provides the MOST rapid reduction in cardiac risk?", o: ["Starting a weight loss program", "Smoking cessation", "Beginning a Mediterranean diet", "Starting yoga for stress management"], a: 1, r: "Smoking cessation provides the most rapid risk reduction: excess cardiac risk drops 50% within 1 year. This is the single most impactful modifiable risk factor for CAD.", s: "Cardiovascular" },
  { q: "A nurse is reviewing medications for four CAD patients. Which order should be QUESTIONED?\n\n1. Atorvastatin 80 mg at bedtime for secondary prevention\n2. Aspirin 81 mg daily for antiplatelet therapy\n3. Amlodipine 5 mg for angina in patient with EF 20%\n4. Isosorbide mononitrate with 12-hour nitrate-free interval", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 2, r: "Amlodipine (a dihydropyridine CCB) can be used cautiously, but the nurse should question any CCB in a patient with EF 20% (severe HFrEF). Non-dihydropyridine CCBs are contraindicated; amlodipine may be acceptable but warrants verification.", s: "Cardiovascular" },
  { q: "A nurse is teaching four patients about stress testing. Which patient would require a PHARMACOLOGIC (not exercise) stress test?\n\n1. 45-year-old marathon runner with atypical chest pain\n2. 70-year-old with severe osteoarthritis unable to walk on a treadmill\n3. 50-year-old with good exercise tolerance and chest tightness\n4. 35-year-old with palpitations during jogging", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patients unable to exercise adequately (severe arthritis, PVD, deconditioning) require pharmacologic stress testing with adenosine/regadenoson (vasodilator) or dobutamine. The other patients can exercise on a treadmill.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients post-cardiac catheterization. Which finding requires IMMEDIATE intervention?\n\n1. Small ecchymosis (2 cm) at radial access site\n2. Absent dorsalis pedis pulse in the leg used for femoral access, with cool and pale foot\n3. Mild back discomfort from lying flat\n4. Mild nausea after contrast administration", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Absent distal pulse with cool pale foot post-femoral catheterization = acute limb ischemia from arterial occlusion, dissection, or embolization. This is a vascular emergency requiring immediate notification and intervention.", s: "Cardiovascular" },
  { q: "A nurse is triaging four patients in a cardiac clinic. Which should be seen FIRST?\n\n1. CAD patient with stable angina asking about exercise prescription\n2. CAD patient reporting new episodes of angina at rest over the past 2 days\n3. Patient requesting statin prescription refill\n4. Patient with controlled hypertension here for routine follow-up", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "New rest angina over 2 days = crescendo/unstable pattern suggesting acute plaque instability. This patient needs urgent evaluation (ECG, troponin) and possible hospital transfer.", s: "Cardiovascular" },
  { q: "A nurse is reviewing four patients' cardiac catheterization results. Which finding indicates the patient needs CABG rather than PCI?\n\n1. Single-vessel 80% RCA stenosis\n2. Left main 90% stenosis with three-vessel disease in a diabetic patient\n3. Single-vessel 70% LAD stenosis with good distal targets\n4. 50% circumflex stenosis", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Left main disease + three-vessel disease in a diabetic patient = CABG preferred over PCI. CABG provides more complete revascularization and better long-term outcomes in this high-risk pattern (SYNTAX/FREEDOM trials).", s: "Cardiovascular" },
  { q: "A nurse is managing four CAD patients' NTG administration. Which patient should NOT receive NTG?\n\n1. CAD patient with SBP 124 and exertional angina\n2. CAD patient with SBP 78 and severe aortic stenosis\n3. CAD patient with SBP 136 and stable angina\n4. CAD patient with SBP 118 requesting NTG before exercise", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "NTG is contraindicated with SBP <90 and in severe aortic stenosis (patients depend on preload for CO through the fixed obstruction; vasodilation causes severe hypotension). Patient 2 has both contraindications.", s: "Cardiovascular" },
  { q: "A nurse is assessing four CAD patients' risk factors. Which patient has the HIGHEST 10-year cardiovascular risk?\n\n1. 40-year-old non-smoker with LDL 130, BP 120/78\n2. 65-year-old male diabetic smoker with LDL 180, BP 158/96, family history of premature CAD\n3. 50-year-old female with LDL 110, BP 128/82\n4. 55-year-old with controlled HTN on medication", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 has the highest risk: multiple non-modifiable (age, male, family history) AND modifiable (smoking, diabetes, uncontrolled HTN, severely elevated LDL) risk factors. This patient needs aggressive multi-factorial intervention.", s: "Cardiovascular" },
  { q: "A nurse is reviewing four patients' coronary calcium scores. Which result requires the MOST aggressive preventive intervention?\n\n1. Calcium score 0 in asymptomatic patient\n2. Calcium score 450 in patient not on any preventive therapy\n3. Calcium score 12 in young patient\n4. Calcium score not yet obtained", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Calcium score 450 indicates significant atherosclerotic burden. This patient needs aggressive preventive therapy: high-intensity statin, antiplatelet, BP optimization, and risk factor modification despite being asymptomatic.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients on dual antiplatelet therapy post-PCI. Which patient situation requires the MOST urgent provider notification?\n\n1. Patient taking aspirin and clopidogrel as prescribed for 6 months post-PCI\n2. Patient who independently stopped clopidogrel after 2 weeks because \"it's too expensive\"\n3. Patient with mild bruising on arms\n4. Patient asking about switching to prasugrel", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Premature discontinuation of P2Y12 inhibitor after PCI dramatically increases stent thrombosis risk — a catastrophic event with high mortality. The provider must be notified immediately to address adherence barriers.", s: "Cardiovascular" },
  { q: "A nurse is educating four CAD patients about the atherosclerotic process. Which patient question reveals the BEST understanding?\n\n1. \"Atherosclerosis is just too much cholesterol in my blood\"\n2. \"I understand that my risk factors damage my artery walls, allowing cholesterol to build up and trigger inflammation that can lead to a heart attack\"\n3. \"Only genetics determine if I'll get heart disease\"\n4. \"Diet has nothing to do with artery disease\"", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 demonstrates comprehensive understanding: risk factors → endothelial damage → LDL infiltration → inflammatory response → plaque formation → potential rupture and MI. This integrated understanding supports better self-management.", s: "Cardiovascular" },
  { q: "A nurse is planning care for four CAD patients. Which nursing diagnosis is the HIGHEST priority for a patient with unstable angina?", o: ["Knowledge deficit related to disease process", "Decreased cardiac output related to impaired myocardial perfusion", "Anxiety related to diagnosis", "Activity intolerance related to angina"], a: 1, r: "Decreased cardiac output from impaired myocardial perfusion is the highest physiological priority (Maslow's hierarchy). While anxiety, knowledge deficit, and activity intolerance are important, they are secondary to perfusion compromise.", s: "Cardiovascular" },
  { q: "A nurse is assigning four CAD patients. Which patient requires the MOST experienced cardiac nurse?\n\n1. Stable angina patient on oral medications for routine follow-up\n2. Patient with unstable angina transitioning to cardiac catheterization lab\n3. CAD patient with well-controlled risk factors for annual check-up\n4. Post-stress test patient with negative results awaiting discharge", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Unstable angina transitioning to cath lab requires experienced judgment for hemodynamic monitoring, medication management, complication recognition, and coordination of care during a high-risk procedure.", s: "Cardiovascular" },
  { q: "A nurse is reviewing four patients' dietary choices. Which meal choice is MOST appropriate for a CAD patient?\n\n1. Fried chicken with mashed potatoes and gravy\n2. Grilled salmon with olive oil, vegetables, and whole grains\n3. Bacon cheeseburger with french fries\n4. Deep-fried fish and chips", o: ["Meal 1", "Meal 2", "Meal 3", "Meal 4"], a: 1, r: "The Mediterranean-style diet (omega-3 rich fish, olive oil, vegetables, whole grains) has the strongest evidence for cardiovascular risk reduction. The other choices are high in saturated fat, trans fat, or sodium.", s: "Cardiovascular" },

  // ===== CARDIOGENIC SHOCK — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four ICU patients. Which should be assessed FIRST?\n\n1. Septic shock patient with MAP 68 on stable norepinephrine drip\n2. Cardiogenic shock patient whose vasopressor drip just ran empty\n3. Post-MI patient with stable vitals on telemetry\n4. HF patient with SpO2 94% on 2L NC", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Vasopressor interruption in cardiogenic shock is immediately life-threatening — the patient will rapidly decompensate without hemodynamic support. This requires immediate intervention to prevent cardiovascular collapse.", s: "Cardiovascular" },
  { q: "A nurse is delegating tasks for four shock patients. Which is appropriate for an LPN?", o: ["Titrating norepinephrine based on MAP readings", "Recording hourly urine output and hemodynamic parameters from the bedside monitor", "Performing initial cardiogenic shock assessment", "Managing IABP timing and settings"], a: 1, r: "Recording numerical values from monitors and urine collection is within LPN scope. Vasopressor titration, initial assessment, and IABP management require RN/critical care expertise.", s: "Cardiovascular" },
  { q: "A nurse is reviewing hemodynamic data for four patients. Which profile indicates cardiogenic shock?\n\n1. CI 3.2, PCWP 8, SVR 900\n2. CI 1.4, PCWP 28, SVR 2200\n3. CI 4.8, PCWP 6, SVR 450\n4. CI 2.8, PCWP 12, SVR 1100", o: ["Profile 1", "Profile 2", "Profile 3", "Profile 4"], a: 1, r: "Low CI (1.4), high PCWP (28 = congestion), high SVR (2200 = compensatory vasoconstriction) = cardiogenic shock. Profile 1 = normal, Profile 3 = septic shock (high CI, low SVR), Profile 4 = near-normal.", s: "Cardiovascular" },
  { q: "A nurse is caring for four shock patients. Which combination of findings indicates the patient is responding to treatment?\n\n1. Rising lactate, decreasing urine output, worsening confusion\n2. Lactate clearance 15%/2hr, improving mental status, urine output 0.6 mL/kg/hr\n3. Stable lactate with unchanged clinical exam\n4. Worsening mottling with increasing vasopressor requirements", o: ["Combination 1", "Combination 2", "Combination 3", "Combination 4"], a: 1, r: "Lactate clearance >10%/2hr + improving mental status + adequate UO = improving tissue perfusion. These multi-organ perfusion indicators together confirm treatment response better than any single marker.", s: "Cardiovascular" },
  { q: "A nurse is managing four patients on inotropes. Which complication requires IMMEDIATE intervention?\n\n1. Milrinone causing mild headache\n2. Dobutamine causing sustained ventricular tachycardia with hypotension\n3. Milrinone causing slight drop in BP (MAP 66→62)\n4. Dobutamine causing mild tachycardia (HR 90→98)", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Sustained VT with hypotension on dobutamine is immediately life-threatening. The arrhythmia must be treated emergently (cardioversion if unstable, antiarrhythmics), and the dobutamine may need to be reduced or discontinued.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which shock type is differentiated by warm, flushed skin with bounding pulses?\n\n1. Cardiogenic shock (cool, mottled, weak pulses)\n2. Hypovolemic shock (cool, pale, thready pulses)\n3. Septic/distributive shock (warm, flushed, bounding pulses)\n4. Obstructive shock (JVD, muffled heart sounds)", o: ["Type 1", "Type 2", "Type 3", "Type 4"], a: 2, r: "Septic shock causes massive vasodilation (warm, flushed skin, bounding pulses) from inflammatory mediators and NO release. This contrasts with cardiogenic and hypovolemic shock where vasoconstriction dominates (cool, pale skin).", s: "Cardiovascular" },
  { q: "A nurse is managing a patient on IABP. Which timing error is MOST dangerous?\n\n1. Early inflation during systole\n2. Early deflation during diastole\n3. Late inflation during diastole\n4. Balloon operating normally", o: ["Error 1", "Error 2", "Error 3", "Error 4"], a: 0, r: "Early inflation (during systole) causes the balloon to oppose ventricular ejection, dramatically increasing afterload and myocardial oxygen demand. This can worsen ischemia and cause hemodynamic collapse. Correct timing is critical.", s: "Cardiovascular" },
  { q: "A nurse is reviewing four patients' lactate trends. Which pattern is MOST concerning?\n\n1. Lactate 2.1 → 1.8 → 1.4 mmol/L over 6 hours\n2. Lactate 1.0 → 1.1 → 1.0 mmol/L (stable normal)\n3. Lactate 4.2 → 6.8 → 9.1 mmol/L despite maximum vasopressor support\n4. Lactate 3.0 → 2.4 → 1.8 mmol/L with treatment", o: ["Pattern 1", "Pattern 2", "Pattern 3", "Pattern 4"], a: 2, r: "Progressively rising lactate despite maximum vasopressor support indicates refractory shock with worsening tissue hypoperfusion. This trajectory is associated with very high mortality and may warrant escalation to mechanical circulatory support.", s: "Cardiovascular" },
  { q: "A nurse is managing four shock patients. Which patient should receive IV fluid resuscitation?\n\n1. Cardiogenic shock with PCWP 26 and bilateral crackles\n2. Hypovolemic shock with PCWP 4 and flat neck veins\n3. Cardiogenic shock with PCWP 22 and pulmonary edema\n4. Cardiogenic shock with PCWP 30 and severe pulmonary edema", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "ONLY Patient 2 (hypovolemic shock) benefits from IV fluids — low PCWP indicates inadequate preload. All cardiogenic shock patients (high PCWP) are already volume-overloaded; fluids would worsen pulmonary edema.", s: "Cardiovascular" },
  { q: "A nurse is monitoring four patients for end-organ damage from cardiogenic shock. Which combination indicates worsening multi-organ dysfunction?\n\n1. UO 0.8 mL/kg/hr, alert and oriented, warm extremities\n2. UO 0.2 mL/kg/hr, confused, cold mottled extremities, AST/ALT rising\n3. UO 0.6 mL/kg/hr, mildly anxious, cool hands that warm with blankets\n4. UO 1.0 mL/kg/hr, alert, normal skin perfusion", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Oliguria + confusion + mottled extremities + rising liver enzymes = multi-organ dysfunction from inadequate tissue perfusion — the cascade from renal, cerebral, peripheral, and hepatic hypoperfusion indicates treatment failure.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which mechanical circulatory support device directly unloads the left ventricle?\n\n1. IABP (inflates/deflates with cardiac cycle)\n2. Impella (microaxial pump across aortic valve)\n3. VA-ECMO (drains from vein, returns to artery)\n4. RVAD (supports right ventricle only)", o: ["Device 1", "Device 2", "Device 3", "Device 4"], a: 1, r: "The Impella directly unloads the LV by aspirating blood from the LV cavity and ejecting it into the ascending aorta. IABP augments but doesn't unload directly. VA-ECMO provides external cardiac support. RVAD supports only the RV.", s: "Cardiovascular" },
  { q: "A nurse is receiving report on a cardiogenic shock patient. Which finding indicates the HIGHEST risk for mortality?\n\n1. Lactate 2.0, MAP 68, CI 2.0 on low-dose pressors\n2. Lactate 12, MAP 52 despite maximal doses of 3 vasopressors, with anuric renal failure\n3. Lactate 3.5, MAP 65, CI 1.8 on single vasopressor\n4. Lactate 1.8, MAP 72, weaning off inotropes", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Lactate 12 + refractory hypotension on maximal triple vasopressor support + anuric renal failure = refractory cardiogenic shock with multi-organ failure. This carries near-100% mortality without mechanical circulatory support or transplant.", s: "Cardiovascular" },
  { q: "A nurse is managing a patient in cardiogenic shock on dobutamine. The patient is also on chronic metoprolol for HF. The dobutamine appears ineffective. What should the nurse anticipate?\n\n1. Increasing dobutamine to maximum dose\n2. Switching to milrinone (PDE-3 inhibitor, works independent of beta receptors)\n3. Adding a second beta-agonist\n4. Discontinuing all vasoactive medications", o: ["Option 1", "Option 2", "Option 3", "Option 4"], a: 1, r: "Chronic beta-blocker therapy downregulates beta receptors, reducing dobutamine effectiveness. Milrinone works via PDE-3 inhibition (bypasses beta receptors entirely), making it effective in beta-blocked patients.", s: "Cardiovascular" },
  { q: "A nurse is assessing four ICU patients. Which assessment technique BEST evaluates tissue perfusion at the bedside?\n\n1. Blood pressure measurement alone\n2. Capillary refill time, skin mottling assessment, mental status, and hourly urine output together\n3. Heart rate monitoring only\n4. CVP reading alone", o: ["Technique 1", "Technique 2", "Technique 3", "Technique 4"], a: 1, r: "Multi-parameter bedside assessment (cap refill, mottling, mental status, UO) provides the best clinical picture of tissue perfusion. No single vital sign adequately reflects end-organ perfusion status.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which patient's norepinephrine extravasation management is CORRECT?\n\n1. Continue the infusion and monitor the site\n2. Stop infusion, elevate the extremity, and apply warm compress only\n3. Stop infusion, inject phentolamine into the affected area, start a new central line\n4. Increase the infusion rate to flush the drug through", o: ["Management 1", "Management 2", "Management 3", "Management 4"], a: 2, r: "Correct extravasation management: stop infusion → inject phentolamine locally (alpha-blocker reverses vasoconstriction) → establish new central venous access. Continuing or increasing the infusion causes tissue necrosis.", s: "Cardiovascular" },
  { q: "A nurse is educating a family about cardiogenic shock. Which statement BEST explains the condition in layperson terms?", o: ["\"The heart has an infection\"", "\"The heart muscle is too weak to pump enough blood to meet the body's needs, so organs aren't getting enough oxygen\"", "\"The blood vessels are too wide\"", "\"There is not enough blood in the body\""], a: 1, r: "Clear, accurate explanation: pump failure causing inadequate organ perfusion. This distinguishes cardiogenic (pump failure) from distributive (vasodilation) and hypovolemic (volume depletion) shock.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients with acute MI. Which patient is at HIGHEST risk for developing cardiogenic shock?\n\n1. Small inferior STEMI, EF 50%, single vessel disease\n2. Massive anterior STEMI (V1-V6), EF 18%, three-vessel disease\n3. NSTEMI with EF 45%, single vessel 70% stenosis\n4. Inferior STEMI with successful PCI, EF 48%", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Massive anterior STEMI with EF 18% and three-vessel disease = highest cardiogenic shock risk. Anterior MIs involve the largest myocardial territory (LAD), and >40% LV loss typically leads to cardiogenic shock.", s: "Cardiovascular" },
  { q: "A nurse is monitoring four patients. Which IABP waveform finding indicates CORRECT timing?\n\n1. Balloon inflation before the dicrotic notch\n2. Augmented diastolic pressure higher than systolic pressure with reduced end-diastolic pressure\n3. Balloon deflation after the onset of systole\n4. No visible augmentation on the arterial waveform", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Correct IABP timing: inflation at dicrotic notch (start of diastole) creates augmented diastolic pressure HIGHER than patient systolic (increasing coronary perfusion), and deflation before systole creates a reduced end-diastolic pressure (reducing afterload).", s: "Cardiovascular" },
  { q: "A nurse is managing four cardiogenic shock patients. Which MAP value requires IMMEDIATE vasopressor titration?\n\n1. MAP 68 on current vasopressor doses\n2. MAP 52 with confusion and mottled extremities\n3. MAP 72 with clear mental status\n4. MAP 66 with adequate urine output", o: ["MAP value 1", "MAP value 2", "MAP value 3", "MAP value 4"], a: 1, r: "MAP 52 with end-organ dysfunction (confusion, mottling) is critically low. Target MAP ≥65 mmHg. Immediate vasopressor uptitration is needed to restore perfusion. The other patients are at or above target with adequate perfusion signs.", s: "Cardiovascular" },
  { q: "A nurse is evaluating treatment response in four cardiogenic shock patients after 4 hours. Which patient shows the BEST response?\n\n1. Lactate unchanged at 6.0, UO 15 mL/hr, confused\n2. Lactate dropping 8.0→5.2→3.8, UO 40 mL/hr, more alert, extremities warming\n3. Lactate rising 4.0→5.5→7.0, UO 10 mL/hr, worsening mottling\n4. Lactate stable at 4.5, UO 20 mL/hr, unchanged exam", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 shows clear improvement: declining lactate (>10% clearance), adequate UO, improving mental status, and warming extremities. This multi-parameter improvement indicates successful resuscitation.", s: "Cardiovascular" },

  // ===== AAA — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four patients. Which should be assessed FIRST?\n\n1. Stable AAA patient (4.0 cm) for routine ultrasound follow-up\n2. Patient with sudden tearing abdominal pain, BP 68/40, and known 6.2 cm AAA\n3. Post-EVAR patient day 2 with stable vitals and intact pedal pulses\n4. AAA patient with BP 138/84 asking about smoking cessation", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Sudden tearing pain + hypotension + known large AAA = ruptured AAA until proven otherwise. This is a surgical emergency with minutes to hours before exsanguination.", s: "Cardiovascular" },
  { q: "A nurse is delegating care for vascular patients. Which task is appropriate for a UAP?", o: ["Assessing pedal pulses post-EVAR", "Measuring hourly vital signs and recording urine output", "Administering IV esmolol for blood pressure control", "Performing neurovascular assessment of lower extremities"], a: 1, r: "Measuring vital signs and recording UO are routine tasks within UAP scope. Pulse assessment, IV medication administration, and neurovascular assessment require nursing judgment.", s: "Cardiovascular" },
  { q: "A nurse is caring for four vascular patients. Which post-EVAR finding requires IMMEDIATE notification?\n\n1. Mild groin soreness at the access site\n2. Absence of right dorsalis pedis and posterior tibial pulses with cold, pale foot\n3. Low-grade temperature of 99.2°F\n4. Mild back discomfort after lying flat", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Absent distal pulses with cold, pale foot = acute limb ischemia from graft limb occlusion, embolization, or vascular injury. This is a vascular emergency requiring immediate intervention.", s: "Cardiovascular" },
  { q: "A nurse is managing four patients in the ED. Which patient with abdominal/back pain should be prioritized for SURGICAL consultation?\n\n1. 35-year-old female with right lower quadrant pain and tenderness (possible appendicitis)\n2. 74-year-old male smoker with sudden severe back pain, BP 76/48, and pulsatile abdominal mass\n3. 45-year-old with gradual onset epigastric pain worse after eating\n4. 60-year-old with chronic low back pain and normal vital signs", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Classic ruptured AAA: elderly male smoker + sudden back pain + hypotension + pulsatile mass. Mortality is near 100% without emergent surgery. Surgical team notification takes highest priority.", s: "Cardiovascular" },
  { q: "A nurse is managing blood products for a ruptured AAA patient. Which transfusion protocol is CORRECT?\n\n1. Crystalloid only until type and crossmatch complete\n2. 1:1:1 ratio of PRBCs:FFP:Platelets with blood warmer and calcium replacement\n3. PRBCs only without FFP or platelets\n4. Dextrose 5% in water for volume resuscitation", o: ["Protocol 1", "Protocol 2", "Protocol 3", "Protocol 4"], a: 1, r: "Massive transfusion protocol: 1:1:1 ratio prevents dilutional coagulopathy, blood warmer prevents hypothermia, and calcium replaces what citrate preservative chelates. This prevents the lethal triad.", s: "Cardiovascular" },
  { q: "A nurse is caring for four AAA patients. Which patient requires the MOST frequent surveillance imaging?\n\n1. 3.5 cm AAA (annual ultrasound)\n2. 5.2 cm AAA in a female patient\n3. 4.0 cm AAA (every 6-12 months)\n4. Post-EVAR patient at 6-month mark", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "5.2 cm AAA in a female patient has reached the repair threshold (≥5.0 cm for women). This patient needs urgent surgical evaluation, not just surveillance. The other patients are in appropriate surveillance protocols.", s: "Cardiovascular" },
  { q: "A nurse is reviewing four patients' blood pressure management. Which AAA patient's BP requires the MOST urgent adjustment?\n\n1. Stable 4.5 cm AAA with SBP 118 on metoprolol\n2. Known 5.8 cm AAA (awaiting surgical date) with SBP 186 and headache\n3. Post-EVAR day 1 with SBP 124\n4. 3.8 cm AAA with SBP 128 on lisinopril", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "SBP 186 in a patient with a 5.8 cm AAA dramatically increases wall stress per Laplace's Law, raising rupture risk. Urgent BP control (target <120) with IV antihypertensive is needed.", s: "Cardiovascular" },
  { q: "A nurse is educating four AAA patients. Which patient statement requires CORRECTION?\n\n1. \"I will take my blood pressure medication every day\"\n2. \"I joined a smoking cessation program\"\n3. \"My doctor said my 4.5 cm aneurysm doesn't need any follow-up\"\n4. \"I will go to the ER immediately if I have sudden severe back pain\"", o: ["Statement 1", "Statement 2", "Statement 3", "Statement 4"], a: 2, r: "A 4.5 cm AAA requires surveillance imaging every 6-12 months. Saying no follow-up is needed is incorrect and dangerous — the aneurysm could enlarge to surgical threshold without monitoring.", s: "Cardiovascular" },
  { q: "A nurse is planning care for a patient with a known 5.5 cm AAA. Which nursing intervention is the HIGHEST priority?\n\n1. Dietary counseling for heart-healthy eating\n2. Educating about emergency symptoms requiring 911 activation\n3. Scheduling annual ophthalmology exam\n4. Reviewing vaccination history", o: ["Intervention 1", "Intervention 2", "Intervention 3", "Intervention 4"], a: 1, r: "At 5.5 cm, the patient is at surgical threshold with significant rupture risk. The highest priority is ensuring the patient recognizes emergency symptoms (sudden severe pain, feeling faint) and knows to call 911 immediately.", s: "Cardiovascular" },
  { q: "A nurse is preparing four patients for surgery. Which AAA patient needs the MOST urgent operating room preparation?\n\n1. Elective EVAR scheduled for tomorrow, stable 5.6 cm AAA\n2. Ruptured AAA with active hemorrhage and dropping hemoglobin\n3. Symptomatic 5.0 cm AAA with intermittent abdominal pain, stable vitals\n4. Post-EVAR patient returning for endoleak repair next week", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Active ruptured AAA with hemorrhage requires the most urgent OR preparation — this patient is actively dying. Every minute of delay increases mortality.", s: "Cardiovascular" },
  { q: "A nurse is monitoring four post-operative AAA patients. Which complication is unique to open surgical repair (not EVAR)?\n\n1. Endoleak\n2. Ischemic bowel from aortic cross-clamp causing mesenteric ischemia\n3. Graft migration\n4. Access site hematoma at the femoral artery", o: ["Complication 1", "Complication 2", "Complication 3", "Complication 4"], a: 1, r: "Aortic cross-clamping during open repair temporarily stops blood flow below the clamp, risking mesenteric ischemia/ischemic bowel. EVAR does not require cross-clamping. Endoleak and graft migration are EVAR-specific.", s: "Cardiovascular" },
  { q: "A nurse is assessing four patients for signs of AAA rupture. Which presentation is MOST consistent with contained retroperitoneal rupture?\n\n1. Sudden severe abdominal pain with hemodynamic instability but temporary stabilization with fluids\n2. Gradual onset mild abdominal discomfort with normal vitals\n3. Chest pain with ST elevation\n4. Lower extremity swelling with positive Homan sign", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 0, r: "Contained retroperitoneal rupture: sudden pain with initial hemodynamic instability that temporarily responds to fluid (the retroperitoneal tissue tamponades the hemorrhage). This is a window of opportunity for emergent surgery before free rupture.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients. Which AAA patient factor increases rupture risk the MOST beyond size alone?\n\n1. Well-controlled hypertension on medication\n2. Active smoking with uncontrolled hypertension and rapid growth (>0.5 cm/6 months)\n3. Former smoker who quit 10 years ago\n4. Regular exercise with normal blood pressure", o: ["Factor 1", "Factor 2", "Factor 3", "Factor 4"], a: 1, r: "Active smoking + uncontrolled HTN + rapid growth = maximal rupture risk factors. Smoking accelerates wall degradation, uncontrolled HTN increases wall stress, and rapid growth indicates structural instability.", s: "Cardiovascular" },
  { q: "A nurse is managing blood pressure for a ruptured AAA patient en route to the OR. The current SBP is 82 mmHg. What is the CORRECT approach?\n\n1. Aggressively resuscitate to SBP 140 with large volume crystalloid\n2. Maintain permissive hypotension (SBP 70-90) to avoid disrupting the retroperitoneal tamponade\n3. Administer vasopressors to achieve SBP >160\n4. No fluid resuscitation of any kind", o: ["Approach 1", "Approach 2", "Approach 3", "Approach 4"], a: 1, r: "Permissive hypotension (SBP 70-90) in ruptured AAA preserves the retroperitoneal clot tamponade. Aggressive resuscitation to normal BP can displace this clot and cause uncontrolled hemorrhage. SBP 82 is within acceptable range.", s: "Cardiovascular" },
  { q: "A nurse is educating a patient about EVAR vs open repair. Which statement about EVAR is CORRECT?\n\n1. \"EVAR eliminates the need for any follow-up\"\n2. \"EVAR is less invasive with shorter recovery but requires lifelong imaging surveillance for endoleak\"\n3. \"EVAR has higher perioperative mortality than open repair\"\n4. \"EVAR can be used for any aneurysm anatomy\"", o: ["Statement 1", "Statement 2", "Statement 3", "Statement 4"], a: 1, r: "EVAR: minimally invasive (percutaneous), shorter recovery, lower 30-day mortality, BUT requires lifelong imaging for endoleak/graft complications and requires suitable anatomy (adequate neck length, iliac access).", s: "Cardiovascular" },
  { q: "A nurse is caring for four AAA patients. Which patient's connective tissue disorder places them at HIGHEST risk for aortic aneurysm at a young age?\n\n1. Patient with osteoarthritis\n2. Patient with Marfan syndrome (fibrillin-1 mutation)\n3. Patient with rheumatoid arthritis\n4. Patient with osteoporosis", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Marfan syndrome (fibrillin-1 defect) causes inherent aortic wall weakness due to defective elastic tissue, predisposing to aneurysm formation at younger ages than typical atherosclerotic AAA.", s: "Cardiovascular" },
  { q: "A nurse is managing four patients. Which post-open AAA repair assessment is the HIGHEST priority in the first 24 hours?\n\n1. Wound appearance\n2. Hourly urine output (assessing for renal ischemia from cross-clamp)\n3. Dietary tolerance\n4. Physical therapy evaluation", o: ["Assessment 1", "Assessment 2", "Assessment 3", "Assessment 4"], a: 1, r: "Post-aortic cross-clamp, renal ischemia is a major concern. Hourly UO monitoring detects early acute tubular necrosis. Also monitor for spinal cord ischemia (lower extremity neuro checks) and mesenteric ischemia (abdominal assessment).", s: "Cardiovascular" },
  { q: "A nurse is triaging four patients. Which vascular emergency has the HIGHEST mortality if not treated within 1 hour?\n\n1. Stable 4.5 cm AAA\n2. Free intraperitoneal AAA rupture\n3. Symptomatic AAA with intermittent pain\n4. Post-EVAR Type II endoleak", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Free intraperitoneal rupture (20% of ruptured AAAs) has near-100% mortality without immediate surgery. Unlike contained retroperitoneal rupture, there is no tissue tamponade — the patient exsanguinates rapidly.", s: "Cardiovascular" },
  { q: "A nurse is caring for four patients with known AAA. Which patient is MOST appropriate for continued surveillance rather than surgical referral?\n\n1. Male with 5.5 cm AAA\n2. Female with 5.2 cm AAA\n3. Male with 4.2 cm AAA, stable growth rate <0.3 cm/year\n4. Patient with symptomatic 4.8 cm AAA causing abdominal pain", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 2, r: "Male with 4.2 cm AAA and slow growth rate = appropriate for surveillance (imaging every 6-12 months). All others have reached surgical criteria: ≥5.5 cm (male), ≥5.0 cm (female), or symptomatic at any size.", s: "Cardiovascular" },

  // ===== ISCHEMIC STROKE — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four patients. Which should be assessed FIRST?\n\n1. Stroke patient 24 hours post-tPA, stable neuro exam, awaiting rehab evaluation\n2. Patient with sudden right-sided weakness and inability to speak, last known well 1 hour ago\n3. TIA patient with completely resolved symptoms being observed\n4. Stroke patient in rehabilitation making steady progress", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Acute stroke within the tPA window (1 hour since LKW, well within 4.5 hours) is the highest priority. 'Time is brain' — 1.9 million neurons die per minute of untreated LVO. Immediate CT and tPA evaluation needed.", s: "Neurological" },
  { q: "A nurse receives four orders for a patient with acute ischemic stroke. Which should be carried out FIRST?\n\n1. Obtain comprehensive metabolic panel\n2. Stat non-contrast CT head\n3. Place Foley catheter\n4. Obtain chest X-ray", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 1, r: "Stat CT is the priority to rule out hemorrhage before tPA administration. Door-to-CT target is <25 minutes. Other orders can be done simultaneously but should not delay CT.", s: "Neurological" },
  { q: "A nurse is caring for four stroke patients. Which finding requires the MOST urgent intervention?\n\n1. Post-tPA patient with stable NIHSS and BP 168/94\n2. Post-tPA patient with sudden headache, vomiting, and pupil dilation\n3. Ischemic stroke patient with mild arm drift\n4. TIA patient with resolved symptoms and BP 146/88", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Sudden headache, vomiting, and pupil dilation post-tPA = hemorrhagic conversion with possible herniation. STOP tPA immediately, stat CT, check coags, and prepare for emergent neurosurgical consultation.", s: "Neurological" },
  { q: "A nurse must delegate tasks for four stroke patients. Which is appropriate for a UAP?", o: ["Performing the swallow screen before meals", "Administering aspirin 325 mg", "Assisting with repositioning and turning the patient every 2 hours", "Performing neurological assessment using NIHSS"], a: 2, r: "Repositioning/turning is within UAP scope and critical for preventing pressure injuries in immobilized stroke patients. Swallow screening, medication administration, and NIHSS assessment require nursing judgment.", s: "Neurological" },
  { q: "A nurse is caring for four stroke patients. Which patient is eligible for IV alteplase?\n\n1. CT shows intracerebral hemorrhage\n2. Last known well 3 hours ago, CT negative for hemorrhage, BP 172/96, NIHSS 12\n3. Stroke onset was 6 hours ago\n4. Patient took warfarin and INR is 4.2", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 meets all criteria: within 4.5-hour window, CT negative for hemorrhage, BP <185/110. Patient 1 = hemorrhage (contraindication), Patient 3 = beyond window, Patient 4 = excessive anticoagulation (contraindication).", s: "Neurological" },
  { q: "A nurse is managing BP for four stroke patients. Which patient's BP management is CORRECT?\n\n1. Pre-tPA: BP 192/112 — administer IV labetalol to lower below 185/110\n2. Post-tPA: BP 188/108 — continue monitoring without intervention\n3. Non-tPA ischemic stroke: BP 210/118 — aggressively lower to 120/80\n4. Pre-tPA: BP 170/94 — hold tPA until BP is lower", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 0, r: "Patient 1 is correct: BP must be <185/110 before tPA. Patient 2 needs intervention (post-tPA target <180/105). Patient 3: aggressive lowering in non-tPA stroke is harmful. Patient 4: BP 170/94 is already <185/110.", s: "Neurological" },
  { q: "A nurse is assessing four stroke patients. Which deficit pattern indicates a LEFT MCA stroke in a right-handed patient?\n\n1. Left leg weakness only\n2. Right face and arm weakness with expressive aphasia\n3. Bilateral leg weakness\n4. Left-sided neglect without weakness", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Left MCA (dominant hemisphere in right-handed) stroke: contralateral (right) face/arm weakness > leg + aphasia (Broca/Wernicke). ACA causes leg > arm. Neglect without weakness suggests non-dominant (right) hemisphere.", s: "Neurological" },
  { q: "A nurse is caring for four stroke patients. Which should NOT receive aspirin today?\n\n1. Ischemic stroke patient who received tPA 18 hours ago\n2. Ischemic stroke patient who did not receive tPA, now 36 hours after onset\n3. TIA patient who has completed stroke workup\n4. Chronic stroke patient on aspirin for secondary prevention", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 0, r: "Aspirin must be held for 24 hours after tPA to reduce hemorrhagic risk. Patient 1 received tPA only 18 hours ago — aspirin should not be given until the 24-hour mark.", s: "Neurological" },
  { q: "A nurse is evaluating four patients' stroke risk factors. Which patient has the HIGHEST stroke risk requiring the MOST aggressive intervention?\n\n1. 50-year-old with controlled hypertension on medication\n2. 72-year-old with atrial fibrillation NOT on anticoagulation, CHA₂DS₂-VASc score of 5\n3. 45-year-old with well-controlled diabetes\n4. 60-year-old non-smoker with normal cholesterol", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "AF with CHA₂DS₂-VASc 5 and NO anticoagulation = extremely high stroke risk. AF increases stroke risk 5-fold. This patient urgently needs anticoagulation for primary stroke prevention.", s: "Neurological" },
  { q: "A nurse is documenting stroke assessments. Which documentation element is MOST critical for treatment eligibility decisions?\n\n1. Allergy list\n2. Last known well time\n3. Insurance information\n4. Emergency contact", o: ["Element 1", "Element 2", "Element 3", "Element 4"], a: 1, r: "Last known well time determines eligibility for tPA (4.5 hours) and thrombectomy (up to 24 hours). Accurate documentation of this single data point can be the difference between treatment eligibility and exclusion.", s: "Neurological" },
  { q: "A nurse is monitoring four post-tPA stroke patients. Which assessment schedule is CORRECT?\n\n1. Neurological checks every 4 hours\n2. Neurological checks q15 min × 2 hr, then q30 min × 6 hr, then hourly × 16 hr\n3. Neurological checks once per shift\n4. Neurological checks only if symptoms change", o: ["Schedule 1", "Schedule 2", "Schedule 3", "Schedule 4"], a: 1, r: "Post-tPA monitoring requires intensive assessment: q15 min × 2 hours → q30 min × 6 hours → hourly × 16 hours. This schedule detects hemorrhagic conversion early, when intervention can still be lifesaving.", s: "Neurological" },
  { q: "A nurse is evaluating four patients for potential LVO amenable to mechanical thrombectomy. Which patient is the BEST candidate?\n\n1. Small lacunar stroke, NIHSS 3, CT perfusion shows no mismatch\n2. Large MCA occlusion, NIHSS 18, CT perfusion shows large penumbra with small core, LKW 8 hours\n3. Patient with NIHSS 2 and resolving symptoms\n4. Patient with massive completed infarct on CT with no penumbra", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2: LVO (MCA) + high NIHSS (≥6) + favorable perfusion mismatch (large penumbra, small core) + within extended window. DAWN/DEFUSE-3 extended thrombectomy to 24 hours with this profile.", s: "Neurological" },
  { q: "A nurse is planning stroke prevention for four patients. Which intervention provides the GREATEST stroke risk reduction for the patient with atrial fibrillation?\n\n1. Aspirin 81 mg daily\n2. Anticoagulation with apixaban (DOAC)\n3. Clopidogrel alone\n4. Lifestyle modification only", o: ["Intervention 1", "Intervention 2", "Intervention 3", "Intervention 4"], a: 1, r: "Anticoagulation (DOACs preferred over warfarin for non-valvular AF) reduces stroke risk by 60-70% in AF. Antiplatelets alone provide inadequate protection against cardioembolic stroke from AF.", s: "Neurological" },
  { q: "A nurse is caring for four stroke patients on day 3. Which finding suggests the MOST dangerous complication?\n\n1. Mild headache with stable exam\n2. Progressive obtundation, dilating right pupil, and declining GCS in a large MCA infarct\n3. Mild swallowing difficulty\n4. Emotional lability", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Progressive obtundation + pupil dilation + declining GCS in large MCA stroke = malignant cerebral edema with uncal herniation (peaks days 2-5). This is a neurosurgical emergency potentially requiring decompressive hemicraniectomy.", s: "Neurological" },
  { q: "A nurse is educating four stroke patients about secondary prevention. Which combination of interventions provides the MOST comprehensive risk reduction?\n\n1. Aspirin alone\n2. Antiplatelet + statin + BP control + lifestyle modification\n3. Lifestyle modification only\n4. Cholesterol management only", o: ["Combination 1", "Combination 2", "Combination 3", "Combination 4"], a: 1, r: "Comprehensive secondary stroke prevention: antiplatelet therapy (aspirin ± clopidogrel for minor stroke), statin (LDL <70), BP control (<130/80), plus lifestyle modification (smoking cessation, exercise, diet). Each component independently reduces recurrence.", s: "Neurological" },
  { q: "A nurse is caring for four patients. Which stroke patient needs an emergent workup for the source of embolism?\n\n1. Lacunar stroke from small vessel disease with known hypertension\n2. Large cortical stroke in multiple vascular territories without identified risk factors\n3. Small vessel stroke with well-controlled diabetes\n4. Stroke patient with known carotid stenosis already scheduled for endarterectomy", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Large cortical strokes in multiple vascular territories suggest cardioembolic source (AF, intracardiac thrombus, valve disease). This pattern requires urgent cardiac evaluation (echocardiogram, prolonged cardiac monitoring).", s: "Neurological" },
  { q: "A nurse is performing a swallow screen on four stroke patients. Which finding indicates the patient should remain NPO?\n\n1. Clear voice quality during conversation\n2. Coughing and wet-gurgling voice quality when drinking 3 oz of water\n3. Able to swallow 3 oz of water without difficulty\n4. Strong cough reflex present", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Coughing and wet/gurgling voice during water swallow test indicate aspiration risk. The patient should remain NPO and receive formal SLP evaluation. Silent aspiration (no cough) is even more dangerous.", s: "Neurological" },
  { q: "A nurse is assessing four stroke patients using the NIHSS. Which total score indicates a SEVERE stroke likely to involve a large vessel occlusion?\n\n1. NIHSS 2\n2. NIHSS 8\n3. NIHSS 22\n4. NIHSS 0", o: ["Score 1", "Score 2", "Score 3", "Score 4"], a: 2, r: "NIHSS 22 = very severe stroke. NIHSS ≥6 suggests possible LVO amenable to thrombectomy. Scores >20 indicate massive neurological deficit with poor prognosis without intervention.", s: "Neurological" },
  { q: "A nurse is teaching four stroke patients about recognizing stroke symptoms. Which mnemonic should be taught for PUBLIC use?\n\n1. NIHSS scale\n2. FAST — Face drooping, Arm weakness, Speech difficulty, Time to call 911\n3. Glasgow Coma Scale\n4. Hunt-Hess classification", o: ["Tool 1", "Tool 2", "Tool 3", "Tool 4"], a: 1, r: "FAST is the validated public education tool for rapid stroke recognition: Face (ask to smile — drooping?), Arm (both up — drift?), Speech (repeat phrase — slurred?), Time (note onset, call 911). It enables rapid EMS activation.", s: "Neurological" },

  // ===== HEMORRHAGIC STROKE — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four neuro patients. Which should be assessed FIRST?\n\n1. SAH patient day 10, stable exam, vasospasm window closing\n2. SAH patient day 7 with new left arm weakness and confusion\n3. ICH patient post-craniotomy day 3 with stable exam\n4. Mild concussion patient with GCS 15", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "New focal deficit on day 7 post-SAH (within vasospasm window days 4-14) = probable delayed cerebral ischemia from vasospasm. Immediate evaluation with TCD and possible angiography/intervention is required.", s: "Neurological" },
  { q: "A nurse is delegating care for neuro ICU patients. Which task is appropriate for an LPN?", o: ["Managing EVD drainage levels", "Recording ICP readings from the bedside monitor every hour", "Titrating nicardipine drip for BP management", "Performing comprehensive neurological assessment"], a: 1, r: "Recording numerical ICP readings from the monitor is within LPN scope. EVD management, vasoactive drip titration, and comprehensive neuro assessment require RN-level critical care expertise.", s: "Neurological" },
  { q: "A nurse is caring for four SAH patients. Which medication administration timing is MOST critical?\n\n1. Stool softener at bedtime\n2. Nimodipine 60 mg exactly every 4 hours without missing doses\n3. Acetaminophen for headache\n4. Multivitamin with morning meal", o: ["Medication 1", "Medication 2", "Medication 3", "Medication 4"], a: 1, r: "Nimodipine must be given ON TIME every 4 hours × 21 days for vasospasm prevention. Missed doses increase vasospasm risk. NEVER give IV (fatal cardiovascular collapse). This is the single most time-critical medication.", s: "Neurological" },
  { q: "A nurse is reviewing four medication orders for hemorrhagic stroke patients. Which order should be IMMEDIATELY questioned?\n\n1. Nicardipine 5 mg/hr IV for ICH with SBP 178\n2. IV alteplase for acute hemorrhagic stroke\n3. Levetiracetam 500 mg IV for seizure prophylaxis\n4. Acetaminophen 650 mg PO for headache", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 1, r: "IV alteplase is ABSOLUTELY CONTRAINDICATED in hemorrhagic stroke — it would dramatically worsen the hemorrhage and is potentially fatal. This order must be questioned immediately.", s: "Neurological" },
  { q: "A nurse is managing four ICH patients. Which BP management approach is CORRECT?\n\n1. Allow BP up to 220/120 as in ischemic stroke\n2. Rapidly reduce SBP to <140 mmHg within 1 hour using IV nicardipine\n3. No BP management needed\n4. Lower SBP to <100 mmHg immediately", o: ["Approach 1", "Approach 2", "Approach 3", "Approach 4"], a: 1, r: "ICH BP target: SBP <140 within 1 hour (INTERACT2/ATACH-2). This differs from ischemic stroke where permissive hypertension is allowed. Nicardipine provides smooth, titratable arterial vasodilation.", s: "Neurological" },
  { q: "A nurse is assessing four post-SAH patients. Which finding indicates the MOST dangerous complication?\n\n1. Mild headache on day 1 post-coiling\n2. Fixed dilated right pupil with contralateral hemiparesis and obtundation\n3. Low-grade fever on day 2\n4. Mild neck stiffness", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Fixed dilated pupil + contralateral weakness + obtundation = uncal herniation. CN III compression causes ipsilateral mydriasis, cerebral peduncle compression causes contralateral hemiparesis. This is a neurosurgical emergency.", s: "Neurological" },
  { q: "A nurse is caring for four SAH patients. Which hyponatremia management is CORRECT?\n\n1. CSW (Na+ 128, hypovolemic) — fluid restriction\n2. SIADH (Na+ 130, euvolemic) — fluid restriction\n3. CSW (Na+ 126, hypovolemic) — hypertonic saline bolus\n4. SIADH (Na+ 132, euvolemic) — normal saline bolus", o: ["Approach 1", "Approach 2", "Approach 3", "Approach 4"], a: 1, r: "SIADH = euvolemic/hypervolemic hyponatremia → treat with fluid restriction. CSW = hypovolemic hyponatremia → treat with normal saline (NOT fluid restriction, which would worsen hypovolemia and vasospasm).", s: "Neurological" },
  { q: "A nurse is prioritizing four neuro patients. Which requires the MOST urgent anticoagulation reversal?\n\n1. Patient on aspirin with minor bruise\n2. Patient on warfarin (INR 3.5) with acute ICH and expanding hematoma\n3. Patient on heparin with aPTT 70 and no bleeding\n4. Patient on apixaban with minor nosebleed", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Warfarin-associated ICH with expanding hematoma requires the most urgent reversal: 4-factor PCC (Kcentra) for rapid reversal + IV vitamin K for sustained effect. Hematoma expansion dramatically worsens outcomes.", s: "Neurological" },
  { q: "A nurse is monitoring an EVD in a post-SAH patient. Which finding requires IMMEDIATE action?\n\n1. CSF drainage of 10 mL/hour (ordered range)\n2. CSF appearance changed from clear to cloudy with temperature spike to 101.8°F\n3. ICP reading of 12 mmHg (normal)\n4. Patient resting comfortably with GCS 14", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Cloudy CSF + fever = possible ventriculitis (EVD-related infection). This is a medical emergency requiring immediate CSF cultures, stat gram stain, and empiric antibiotics. Delay increases mortality.", s: "Neurological" },
  { q: "A nurse is planning care for four hemorrhagic stroke patients. Which head position is CORRECT?\n\n1. HOB flat to maximize cerebral perfusion\n2. HOB 30 degrees with head midline to promote venous drainage and reduce ICP\n3. Trendelenburg position\n4. HOB 90 degrees (sitting upright)", o: ["Position 1", "Position 2", "Position 3", "Position 4"], a: 1, r: "Hemorrhagic stroke: HOB 30° promotes cerebral venous drainage (reduces ICP). Head MIDLINE prevents jugular vein compression. This differs from ischemic stroke (HOB flat to maximize perfusion).", s: "Neurological" },
  { q: "A nurse is reviewing four patients' CT scan results. Which finding predicts the HIGHEST risk of hematoma expansion in ICH?\n\n1. Small hematoma <10 mL without contrast extravasation\n2. Large hematoma with 'spot sign' (active contrast extravasation on CTA)\n3. Small chronic subdural hematoma\n4. Normal CT head", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "The spot sign (active contrast extravasation within the hematoma on CTA) indicates ongoing bleeding and predicts hematoma expansion — the strongest predictor of clinical deterioration in ICH. Requires aggressive BP control.", s: "Neurological" },
  { q: "A nurse is assessing four neuro patients for the Cushing triad. Which combination of findings represents this late sign of herniation?\n\n1. Tachycardia + hypotension + rapid respirations\n2. Hypertension + bradycardia + irregular respirations\n3. Hypotension + tachycardia + fever\n4. Normal vital signs", o: ["Combination 1", "Combination 2", "Combination 3", "Combination 4"], a: 1, r: "Cushing triad: hypertension (reflex to maintain cerebral perfusion), bradycardia (vagal response), irregular respirations (brainstem compression). This is a LATE, OMINOUS sign of impending herniation.", s: "Neurological" },
  { q: "A nurse is managing four patients. Which seizure prophylaxis approach is CORRECT for SAH?\n\n1. Phenytoin for all SAH patients\n2. Levetiracetam preferred over phenytoin due to better cognitive outcomes in SAH\n3. No seizure prophylaxis needed\n4. Valproic acid as first-line", o: ["Approach 1", "Approach 2", "Approach 3", "Approach 4"], a: 1, r: "Levetiracetam is preferred over phenytoin in SAH — studies show phenytoin is associated with worse cognitive outcomes, increased medical complications, and possible worsened vasospasm in SAH patients.", s: "Neurological" },
  { q: "A nurse is assessing four SAH patients during the vasospasm window. Which transcranial Doppler finding indicates developing vasospasm?\n\n1. MCA velocity 80 cm/s (normal)\n2. MCA velocity 220 cm/s (markedly elevated)\n3. MCA velocity 60 cm/s\n4. Unable to obtain readings", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "TCD velocity >200 cm/s in the MCA indicates severe vasospasm (narrowed vessel = faster flow per Bernoulli's principle). This requires immediate clinical correlation and possible angiographic intervention.", s: "Neurological" },
  { q: "A nurse is managing four hemorrhagic stroke patients. Which patient is at HIGHEST risk for rebleeding?\n\n1. SAH patient with secured (coiled) aneurysm on day 3\n2. SAH patient with unsecured aneurysm, elevated BP, and agitation on day 1\n3. ICH patient with well-controlled BP on day 5\n4. SAH patient with secured (clipped) aneurysm on day 7", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Unsecured aneurysm on day 1 + elevated BP + agitation = maximal rebleeding risk. Day 1 carries 4% rebleeding risk, highest without securing. Uncontrolled BP and agitation increase wall stress on the unsecured aneurysm.", s: "Neurological" },
  { q: "A nurse is reviewing the ICH Score for four patients. Which combination predicts the HIGHEST 30-day mortality?\n\n1. GCS 14, ICH 15 mL, no IVH, supratentorial, age 55\n2. GCS 5, ICH 45 mL, IVH present, infratentorial, age 82\n3. GCS 12, ICH 20 mL, no IVH, supratentorial, age 60\n4. GCS 15, ICH 8 mL, no IVH, supratentorial, age 45", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 ICH Score: GCS 3-4=2pts, volume >30mL=1pt, IVH=1pt, infratentorial=1pt, age >80=1pt = 6 points (near-100% 30-day mortality). This guides goals-of-care discussions with the family.", s: "Neurological" },

  // ===== SEIZURES — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four patients. Which should be assessed FIRST?\n\n1. Epilepsy patient with phenytoin level 16 (therapeutic 10-20) and mild headache\n2. Patient in continuous generalized tonic-clonic seizure for 7 minutes\n3. Post-seizure patient resting comfortably in the post-ictal phase\n4. Epilepsy patient asking about medication refills", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Continuous seizure >5 minutes = status epilepticus. This is a medical emergency with progressive neuronal death and increasing treatment resistance. Immediate IV benzodiazepine is required.", s: "Neurological" },
  { q: "A nurse must delegate tasks. Which is appropriate for a UAP during seizure precautions?", o: ["Administering rectal diazepam during a seizure", "Staying at the bedside and calling for help if a seizure begins", "Performing post-ictal neurological assessment", "Adjusting AED dosing"], a: 1, r: "UAPs can provide continuous observation and activate the emergency response. Medication administration, neurological assessment, and medication management require nursing licensure.", s: "Neurological" },
  { q: "A nurse is reviewing four patients' AED levels. Which result requires IMMEDIATE intervention?\n\n1. Phenytoin 18 mcg/mL (therapeutic 10-20)\n2. Phenytoin 32 mcg/mL with nystagmus, ataxia, and slurred speech\n3. Levetiracetam — no level ordered (not needed)\n4. Valproic acid 85 mcg/mL (therapeutic 50-100)", o: ["Result 1", "Result 2", "Result 3", "Result 4"], a: 1, r: "Phenytoin 32 with toxicity symptoms (nystagmus, ataxia, slurred speech) requires immediate intervention: hold phenytoin, notify provider, monitor for worsening toxicity. Due to zero-order kinetics, levels can continue rising.", s: "Neurological" },
  { q: "A nurse is managing four seizure patients' medications. Which order should be QUESTIONED?\n\n1. Levetiracetam 500 mg IV BID for a post-neurosurgery patient\n2. Phenytoin mixed in D5W for IV infusion\n3. Lorazepam 0.1 mg/kg IV for status epilepticus\n4. Valproic acid 500 mg PO BID for generalized epilepsy", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 1, r: "Phenytoin precipitates in dextrose solutions — it must ONLY be mixed with normal saline. D5W administration causes crystallization that can occlude IV lines and cause emboli. This order must be questioned.", s: "Neurological" },
  { q: "A nurse is caring for four patients on AEDs. Which patient situation poses the GREATEST safety risk?\n\n1. Epilepsy patient on carbamazepine with stable seizure control × 2 years\n2. Epilepsy patient who abruptly stopped all AEDs 2 days ago against medical advice\n3. Patient on levetiracetam reporting mild fatigue\n4. Patient on valproic acid with therapeutic level and no side effects", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Abrupt AED discontinuation is the highest risk — the brain, adapted to the anticonvulsant effect, becomes hyperexcitable. Risk of rebound seizures, status epilepticus, and SUDEP (sudden unexpected death in epilepsy).", s: "Neurological" },
  { q: "A nurse is prioritizing education for four epilepsy patients at discharge. Which teaching point is MOST critical for patient safety?\n\n1. How to keep a seizure diary\n2. Never stop AEDs abruptly, and understand when to call 911 for prolonged seizures\n3. Dietary considerations\n4. When to schedule next EEG", o: ["Topic 1", "Topic 2", "Topic 3", "Topic 4"], a: 1, r: "Never stopping AEDs abruptly (risk of SE) and knowing when to call 911 for prolonged seizures (>5 minutes) are the most critical safety points. These can be life-saving.", s: "Neurological" },
  { q: "A nurse is managing SE treatment. Lorazepam was given twice without effect. What is the NEXT step?\n\n1. Give a third dose of lorazepam\n2. Administer fosphenytoin, levetiracetam, or valproate IV as second-line agent\n3. Continue observation\n4. Administer oral carbamazepine", o: ["Step 1", "Step 2", "Step 3", "Step 4"], a: 1, r: "SE treatment ladder: 1st-line (lorazepam × 2 doses) failed → 2nd-line: fosphenytoin 20 mg PE/kg, levetiracetam 60 mg/kg, or valproate 40 mg/kg IV. If this fails → 3rd-line: continuous infusion with EEG monitoring.", s: "Neurological" },
  { q: "A nurse is reviewing four patients' AED prescriptions. Which patient's medication choice is MOST concerning?\n\n1. 25-year-old woman on lamotrigine planning pregnancy\n2. 30-year-old woman on valproic acid who just discovered she is 6 weeks pregnant\n3. 60-year-old man on levetiracetam for post-stroke seizures\n4. 45-year-old on carbamazepine with therapeutic level", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Valproic acid is highly teratogenic (1-2% neural tube defect risk). A 6-weeks-pregnant patient on valproate needs urgent provider consultation about switching to a safer AED (lamotrigine/levetiracetam) while balancing seizure control.", s: "Neurological" },
  { q: "A nurse witnesses a generalized tonic-clonic seizure. Which action should be performed FIRST?\n\n1. Insert a padded tongue blade\n2. Restrain the extremities to prevent injury\n3. Note the time and turn the patient to the side\n4. Administer oral medication immediately", o: ["Action 1", "Action 2", "Action 3", "Action 4"], a: 2, r: "Time the seizure (critical for determining SE) and turn to the side (maintain airway, prevent aspiration). NEVER insert anything in the mouth (aspiration risk) or restrain (fracture risk). Call for help.", s: "Neurological" },
  { q: "A nurse is assessing four post-ictal patients. Which finding is MOST concerning and requires ADDITIONAL workup?\n\n1. Post-ictal confusion lasting 15 minutes then clearing\n2. Todd paralysis (left arm weakness) that has persisted >48 hours without improvement\n3. Brief post-ictal drowsiness resolving within 30 minutes\n4. Post-ictal headache responding to acetaminophen", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Todd paralysis typically resolves within 24-48 hours. Persistent focal weakness >48 hours without improvement warrants additional workup (brain imaging) to rule out structural lesion or actual stroke.", s: "Neurological" },
  { q: "A nurse is caring for four hospitalized patients with new-onset seizures. Which metabolic cause should be investigated FIRST?\n\n1. Check thyroid function\n2. Check blood glucose and serum sodium\n3. Check liver function tests\n4. Check vitamin B12 level", o: ["Test 1", "Test 2", "Test 3", "Test 4"], a: 1, r: "Hypoglycemia and hyponatremia are the most common metabolic causes of provoked seizures and are immediately treatable. Checking glucose and sodium first can identify a rapidly correctable cause.", s: "Neurological" },
  { q: "A nurse is reviewing four patients' seizure documentation. Which documentation is MOST complete and helpful?\n\n1. \"Patient had a seizure\"\n2. \"Generalized tonic-clonic seizure, onset 14:32, duration 2 min 15 sec, began with right arm jerking then generalized, loss of consciousness, urinary incontinence, post-ictal confusion × 20 min\"\n3. \"Seizure occurred, gave medications\"\n4. \"Patient shaking in bed\"", o: ["Documentation 1", "Documentation 2", "Documentation 3", "Documentation 4"], a: 1, r: "Comprehensive documentation includes: seizure type, exact timing, duration, body parts involved, progression pattern, LOC changes, incontinence, post-ictal state and duration. This information guides diagnosis and treatment.", s: "Neurological" },
  { q: "A nurse is managing four patients on AEDs who need surgery. Which perioperative medication management is CORRECT?\n\n1. Hold all AEDs for 24 hours before surgery\n2. Continue AEDs via alternative route (IV or NG tube) if NPO\n3. Give half the usual dose on surgery day\n4. Switch all AEDs to IV phenytoin regardless of current medication", o: ["Management 1", "Management 2", "Management 3", "Management 4"], a: 1, r: "AEDs must continue perioperatively (stress, sleep deprivation, medication gaps are seizure triggers). If NPO, use IV formulations or administer via NG tube. Most AEDs have IV equivalents or can be crushed for NG administration.", s: "Neurological" },
  { q: "A nurse is caring for four epilepsy patients. Which patient's activity restriction counseling is MOST important?\n\n1. Patient with well-controlled seizures asking about walking program\n2. Patient with uncontrolled seizures asking about swimming alone in a pool\n3. Patient asking about dietary modifications\n4. Patient asking about joining a support group", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Swimming alone with uncontrolled seizures is extremely dangerous — drowning risk is 15-19 times higher in epilepsy. Patients should NEVER swim alone, always use a buddy system, and avoid water activities when seizures are uncontrolled.", s: "Neurological" },

  // ===== MENINGITIS — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four patients. Which should be assessed FIRST?\n\n1. Meningitis patient on antibiotics × 48 hours, improving clinically\n2. Patient with fever 103.2°F, severe headache, and nuchal rigidity — meningitis suspected but NOT yet treated\n3. Post-LP patient with mild positional headache\n4. Viral meningitis patient with stable symptoms", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Suspected untreated bacterial meningitis is the highest emergency — mortality increases ~30%/hour of antibiotic delay. This patient needs empiric antibiotics IMMEDIATELY, even before LP or CT.", s: "Neurological" },
  { q: "A nurse receives four orders for a suspected meningitis patient. Which should be carried out FIRST?\n\n1. Obtain CT scan\n2. Send blood cultures\n3. Administer empiric IV antibiotics\n4. Perform lumbar puncture", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 2, r: "Antibiotics FIRST — always. Blood cultures can be drawn simultaneously if a vein is available, but NEVER delay antibiotics for any test. CT and LP can follow, but antibiotics must not wait.", s: "Neurological" },
  { q: "A nurse must delegate tasks for four meningitis patients. Which is appropriate for a UAP?", o: ["Administering IV ceftriaxone", "Applying droplet precautions equipment (mask) before entering the room", "Performing neurological assessment", "Determining isolation precaution type"], a: 1, r: "UAPs can apply appropriate PPE (masks for droplet precautions) before room entry. Medication administration, neurological assessment, and infection control decision-making require nursing judgment.", s: "Neurological" },
  { q: "A nurse is reviewing four patients' CSF results. Which pattern indicates BACTERIAL meningitis?\n\n1. WBC 45 (lymphocytes), glucose 65, protein 55\n2. WBC 2500 (95% neutrophils), glucose 22, protein 280\n3. WBC 5, glucose 70, protein 30 (normal)\n4. RBC 15,000 with xanthochromia", o: ["Result 1", "Result 2", "Result 3", "Result 4"], a: 1, r: "WBC 2500 with 95% neutrophils (neutrophilic pleocytosis) + glucose 22 (very low — bacteria/neutrophils consume glucose) + protein 280 (elevated — BBB disruption) = classic bacterial meningitis. Pattern 1 = viral, Pattern 4 = SAH.", s: "Neurological" },
  { q: "A nurse is managing dexamethasone timing for four meningitis patients. Which administration is CORRECT?\n\n1. Dexamethasone given 2 hours after first antibiotic dose\n2. Dexamethasone given 15 minutes BEFORE the first antibiotic dose\n3. Dexamethasone given 24 hours after antibiotics\n4. Dexamethasone not given at all", o: ["Timing 1", "Timing 2", "Timing 3", "Timing 4"], a: 1, r: "Dexamethasone MUST be given 15-20 minutes BEFORE or simultaneously with the first antibiotic dose. Starting after antibiotics provides NO benefit — it must suppress the inflammatory surge BEFORE bacterial lysis occurs.", s: "Neurological" },
  { q: "A nurse is caring for four patients. Which meningitis patient requires droplet precautions?\n\n1. Patient with confirmed pneumococcal meningitis\n2. Patient with suspected meningococcal meningitis, cultures pending\n3. Patient with confirmed viral meningitis\n4. Patient with fungal meningitis", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Droplet precautions are required for SUSPECTED meningococcal meningitis until ruled out or 24 hours of effective antibiotics. N. meningitidis is transmitted via respiratory droplets. Other meningitis types need standard precautions only.", s: "Neurological" },
  { q: "A nurse is managing prophylaxis for contacts of a meningococcal meningitis patient. Which contact requires chemoprophylaxis?\n\n1. Nurse who briefly entered the room wearing a mask\n2. Patient's spouse who has been sleeping in the same bed\n3. Hospital visitor who passed the room in the hallway\n4. Lab technician who processed the CSF sample", o: ["Contact 1", "Contact 2", "Contact 3", "Contact 4"], a: 1, r: "Close contacts (household members, intimate contacts, direct exposure to respiratory secretions) need prophylaxis: ciprofloxacin single dose or rifampin × 2 days. Brief masked contact and indirect exposure do not qualify.", s: "Neurological" },
  { q: "A nurse is monitoring four meningitis patients for complications. Which finding indicates the MOST serious complication?\n\n1. Mild headache on day 2 of antibiotics\n2. Rapidly spreading petechial rash progressing to purpura with dropping BP\n3. Low-grade fever that is improving\n4. Mild photophobia with dim lighting tolerance", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Petechial rash → purpura + hypotension = meningococcemia with DIC, possibly progressing to Waterhouse-Friderichsen syndrome (bilateral adrenal hemorrhage). This is immediately life-threatening.", s: "Neurological" },
  { q: "A nurse is reviewing four patients' vancomycin administration. Which finding indicates a rate-dependent reaction (NOT a true allergy)?\n\n1. Anaphylaxis with throat swelling after second dose\n2. Flushing and erythema of upper body during rapid IV infusion (Red Man syndrome)\n3. Elevated creatinine after 7 days of therapy\n4. Ototoxicity with hearing changes", o: ["Finding 1", "Finding 2", "Finding 3", "Finding 4"], a: 1, r: "Red Man syndrome = histamine-mediated flushing from rapid infusion. NOT a true allergy. Prevented by infusing over ≥60 minutes. Does not contraindicate future vancomycin use. Anaphylaxis IS a true allergy.", s: "Neurological" },
  { q: "A nurse is caring for four meningitis patients. Which patient's sodium level requires the MOST urgent intervention?\n\n1. Na+ 140 mEq/L (normal)\n2. Na+ 118 mEq/L with confusion and lethargy (SIADH complication)\n3. Na+ 136 mEq/L\n4. Na+ 132 mEq/L with stable symptoms", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Na+ 118 with neurological symptoms (confusion, lethargy) = severe symptomatic hyponatremia requiring urgent treatment. Risk of seizures and cerebral edema. Requires hypertonic saline consideration with careful correction rate monitoring.", s: "Neurological" },

  // ===== PARKINSON DISEASE — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four PD patients. Which should be assessed FIRST?\n\n1. PD patient with mild resting tremor asking about medication timing\n2. PD patient who fell, hit their head, and is now confused and increasingly drowsy\n3. PD patient with end-of-dose wearing off asking about dose adjustment\n4. PD patient with constipation requesting a laxative", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Head injury with confusion and progressive drowsiness = possible intracranial hemorrhage (subdural hematoma common in elderly fallers). Requires immediate neurological assessment and CT head.", s: "Neurological" },
  { q: "A nurse must delegate care for four PD patients. Which task is appropriate for a UAP?", o: ["Assessing gait and balance for fall risk", "Assisting with ambulation using proper safety techniques", "Evaluating medication effectiveness", "Teaching about protein interaction with levodopa"], a: 1, r: "Safe ambulation assistance is within UAP scope and critical for PD patients (high fall risk). Gait assessment, medication evaluation, and complex education require nursing judgment.", s: "Neurological" },
  { q: "A nurse is reviewing four PD patients' medication orders. Which should be IMMEDIATELY questioned?\n\n1. Carbidopa-levodopa 25/100 TID, 30 minutes before meals\n2. Haloperidol 5 mg for agitation in a PD patient\n3. Pramipexole 0.25 mg TID with gradual dose titration\n4. Entacapone 200 mg with each levodopa dose", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 1, r: "Haloperidol (typical antipsychotic/dopamine blocker) in PD = catastrophic worsening of parkinsonism. Dopamine blockers are CONTRAINDICATED in PD. If antipsychotic needed, quetiapine or clozapine (weak D2 blockade) may be considered.", s: "Neurological" },
  { q: "A nurse is caring for four PD patients. Which finding requires the MOST urgent intervention?\n\n1. Mild tremor during rest that decreases with intentional movement\n2. Patient found rigid, confused, febrile to 104°F after carbidopa-levodopa was inadvertently held for 2 days\n3. Patient reporting occasional constipation\n4. Patient with mild masked facies during conversation", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Rigidity + confusion + high fever after levodopa discontinuation = parkinsonism-hyperpyrexia syndrome (resembles NMS). This is life-threatening. Resume levodopa immediately, provide supportive care, and notify provider urgently.", s: "Neurological" },
  { q: "A nurse is prioritizing four PD patients at risk for complications. Which patient is at HIGHEST fall risk?\n\n1. Early-stage PD with unilateral resting tremor, independent ambulation\n2. Advanced PD with postural instability, freezing of gait, orthostatic hypotension, and history of 3 falls this month\n3. PD patient on stable medications with no balance complaints\n4. Newly diagnosed PD patient with mild bradykinesia only", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Advanced PD + postural instability + freezing + orthostatic hypotension + recent fall history = extreme fall risk. This patient needs comprehensive fall prevention: PT referral, home safety assessment, assistive devices, and orthostatic precautions.", s: "Neurological" },
  { q: "A nurse is managing four PD patients' medication timing. Which patient's request should take the HIGHEST priority?\n\n1. PD patient asking for PRN acetaminophen for headache\n2. PD patient whose scheduled carbidopa-levodopa is 30 minutes overdue and is becoming immobile\n3. PD patient requesting dietary counseling\n4. PD patient asking about a support group", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Levodopa timing is critical in PD — delayed doses cause rapid motor deterioration (off state with immobility, rigidity). The 30-minute delay is already causing functional decline. Administer immediately.", s: "Neurological" },
  { q: "A nurse is screening four PD patients for impulse control disorders. Which patient's behavior is MOST consistent with dopamine agonist-related ICD?\n\n1. Patient planning a reasonable family vacation\n2. Patient who has spent $15,000 in online gambling this month (no previous gambling history) since starting pramipexole\n3. Patient who enjoys cooking as a hobby\n4. Patient who reads books for entertainment", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "New-onset compulsive gambling with significant financial loss temporally related to dopamine agonist initiation = classic ICD. This affects 15-20% of patients on DAs. Requires immediate provider notification for medication adjustment.", s: "Neurological" },
  { q: "A nurse is preparing a PD patient for surgery. Which medication order requires clarification?\n\n1. Continue carbidopa-levodopa via NG tube during NPO period\n2. Hold all PD medications the day of surgery and resume when patient is eating\n3. Continue pramipexole on schedule\n4. Administer PRN antiemetic (ondansetron) as needed post-op", o: ["Order 1", "Order 2", "Order 3", "Order 4"], a: 1, r: "Holding ALL PD medications during surgery is dangerous — can precipitate parkinsonism-hyperpyrexia syndrome. Levodopa must continue via NG tube if NPO. This order needs immediate clarification.", s: "Neurological" },
  { q: "A nurse is assessing four PD patients' swallowing. Which patient needs the MOST urgent SLP referral?\n\n1. Patient with normal swallow function and no complaints\n2. Patient with coughing during meals, wet voice after eating, and recent 10-pound weight loss\n3. Patient with occasional throat clearing during liquids\n4. Patient with no mealtime difficulties", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Coughing during meals + wet voice (suggests laryngeal penetration) + weight loss = significant dysphagia with aspiration risk. Aspiration pneumonia is a leading cause of death in PD. Urgent SLP evaluation is critical.", s: "Neurological" },
  { q: "A nurse is educating four PD patients. Which statement indicates CORRECT understanding of the disease?\n\n1. \"PD is cured by taking levodopa\"\n2. \"PD is a progressive disease where my medications will need adjustment over time, and exercise can help slow progression\"\n3. \"Once I start medications, I'll never have symptoms again\"\n4. \"PD only affects movement\"", o: ["Statement 1", "Statement 2", "Statement 3", "Statement 4"], a: 1, r: "Correct understanding: PD is progressive, medications require ongoing adjustment, and exercise has neuroprotective benefits. PD affects both motor and non-motor functions. Levodopa treats symptoms but does not cure.", s: "Neurological" },

  // ===== DELIRIUM VS DEMENTIA — ADAPTIVE CAT (20 questions) =====
  { q: "A nurse is caring for four elderly patients. Which should be assessed FIRST?\n\n1. Alzheimer patient at baseline with stable confusion, eating dinner with assistance\n2. Patient who was alert and oriented this morning but is now acutely confused, agitated, and pulling at IV lines\n3. Dementia patient sleeping comfortably\n4. Mild cognitive impairment patient oriented × 3 asking about dinner", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Acute onset confusion (alert this morning → confused now) = delirium until proven otherwise. This is a medical emergency requiring immediate cause identification — the underlying trigger may be life-threatening (sepsis, MI, medication toxicity).", s: "Neurological" },
  { q: "A nurse is delegating care for four elderly patients with cognitive changes. Which is appropriate for a UAP?", o: ["Administering haloperidol for agitation", "Sitting with the delirious patient, providing reorientation, and ensuring safety", "Determining whether confusion is delirium or dementia", "Performing the CAM assessment"], a: 1, r: "UAPs can provide 1:1 observation, reorientation, and safety monitoring. Medication administration, differential diagnosis, and formal cognitive screening require nursing judgment.", s: "Neurological" },
  { q: "A nurse is reviewing four patients' medication lists for delirium risk. Which patient's medication profile creates the HIGHEST delirium risk?\n\n1. Metoprolol 25 mg, lisinopril 10 mg, aspirin 81 mg\n2. Diphenhydramine 50 mg, oxybutynin 5 mg, amitriptyline 25 mg, lorazepam 1 mg\n3. Acetaminophen 500 mg PRN, multivitamin daily\n4. Omeprazole 20 mg, amlodipine 5 mg", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 has FOUR medications on the Beers Criteria for elderly: diphenhydramine (anticholinergic), oxybutynin (anticholinergic), amitriptyline (TCA/anticholinergic), and lorazepam (benzodiazepine). Extreme delirium risk from anticholinergic burden.", s: "Neurological" },
  { q: "A nurse is assessing four confused elderly patients. Which presentation is MOST consistent with delirium rather than dementia?\n\n1. Gradual onset memory loss over 2 years with preserved attention\n2. Acute onset confusion that fluctuates throughout the day with visual hallucinations\n3. Slowly progressive personality changes with behavioral disinhibition\n4. Gradual stepwise cognitive decline following vascular events", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Acute onset + fluctuating course + visual hallucinations = delirium hallmarks. Patient 1 = Alzheimer, Patient 3 = frontotemporal dementia, Patient 4 = vascular dementia. All dementias have gradual onset.", s: "Neurological" },
  { q: "A nurse is implementing delirium prevention for four high-risk hospitalized elderly patients. Which intervention bundle is MOST evidence-based?\n\n1. Physical restraints and sedating medications\n2. Frequent reorientation, early mobilization, sensory aids (glasses/hearing aids), sleep hygiene, and adequate hydration\n3. Continuous sedation to prevent agitation\n4. Keeping the room lights on 24 hours", o: ["Bundle 1", "Bundle 2", "Bundle 3", "Bundle 4"], a: 1, r: "HELP (Hospital Elder Life Program) bundle: reorientation, early mobilization, sensory aids, sleep-wake cycle normalization, hydration, and nutrition. Evidence shows 30-40% reduction in delirium incidence. Restraints and sedation WORSEN delirium.", s: "Neurological" },
  { q: "A nurse is managing four patients with behavioral disturbances. Which patient might SAFELY receive low-dose haloperidol?\n\n1. Patient with Lewy body dementia and agitation\n2. Patient with delirium who is severely agitated and at risk of self-harm despite non-pharmacological measures\n3. Patient with mild sundowning responding to reorientation\n4. Dementia patient who is pleasantly confused and cooperative", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Low-dose haloperidol only for severely agitated delirium when non-pharmacological measures fail AND the patient is a danger. Lewy body dementia = absolute contraindication (fatal neuroleptic sensitivity). Patients 3 and 4 don't need medication.", s: "Neurological" },
  { q: "A nurse is investigating the cause of acute delirium in four patients. Which workup combination is MOST appropriate?\n\n1. Only check blood pressure\n2. UA, CBC, BMP (glucose, sodium, calcium), medication review, pain assessment, chest X-ray\n3. Only perform a brain MRI\n4. Only review the medication list", o: ["Workup 1", "Workup 2", "Workup 3", "Workup 4"], a: 1, r: "Comprehensive delirium workup: UA (UTI), CBC (infection), BMP (metabolic — glucose, sodium, calcium), medication review (anticholinergics, new medications, dose changes), pain assessment, and CXR (pneumonia). No single test is sufficient.", s: "Neurological" },
  { q: "A nurse is caring for four elderly patients. Which combination of factors places a patient at the HIGHEST risk for delirium?\n\n1. 50-year-old with no cognitive impairment, no medications\n2. 85-year-old with pre-existing dementia, on diphenhydramine, with UTI and Foley catheter\n3. 65-year-old with controlled hypertension, alert and oriented\n4. 70-year-old with mild hearing loss but otherwise healthy", o: ["Patient 1", "Patient 2", "Patient 3", "Patient 4"], a: 1, r: "Patient 2 has multiple compounding risk factors: advanced age, pre-existing dementia (strongest risk factor), anticholinergic medication, active infection (UTI), and Foley catheter (delirium risk factor). This patient needs aggressive delirium prevention.", s: "Neurological" },
  { q: "A nurse is differentiating delirium, depression, and dementia in four patients. Which cognitive domain assessment BEST distinguishes delirium?\n\n1. Long-term memory recall\n2. Attention testing (spell WORLD backward, serial 7s, months backward)\n3. Language fluency\n4. Visuospatial ability", o: ["Assessment 1", "Assessment 2", "Assessment 3", "Assessment 4"], a: 1, r: "ATTENTION is the key distinguishing feature of delirium. Inattention (inability to focus, easily distractible) is the hallmark. Dementia impairs memory first. Depression preserves attention but reduces motivation. Test with serial 7s, WORLD backward, or digit span.", s: "Neurological" },
  { q: "A nurse is caring for four dementia patients' families. Which family's concerns should be addressed MOST urgently?\n\n1. Family asking about community support groups\n2. Primary caregiver reporting feeling overwhelmed, not eating, not sleeping, and having thoughts of harming the patient\n3. Family asking about long-term care options\n4. Family inquiring about medication management", o: ["Family 1", "Family 2", "Family 3", "Family 4"], a: 1, r: "Caregiver expressing overwhelm with self-neglect (not eating/sleeping) and thoughts of harming the patient = immediate safety concern for both caregiver and patient. Requires urgent intervention: safety assessment, respite care, crisis resources.", s: "Neurological" }
];
